#!/usr/bin/env python3
"""Unified Nishizumi launcher that embeds the Fuel, Pit Time, Tire Wear, and Traction apps in one file."""

from __future__ import annotations

import os
import subprocess
import sys
import tkinter as tk
from pathlib import Path
from typing import Dict, Optional

APP_DEFINITIONS = [
    ('fuel', 'Fuel Monitor'),
    ('pittime', 'Pit Time Overlay'),
    ('tirewear', 'Tire Wear Overlay'),
    ('traction', 'Traction Overlay'),
]

EMBEDDED_APPS: Dict[str, str] = {
    'fuel': '#!/usr/bin/env python3\n"""Tkinter overlay for smart fuel consumption monitoring in iRacing."""\n\nfrom __future__ import annotations\n\nimport json\nimport math\nimport os\nimport sys\nimport time\nimport tkinter as tk\nfrom dataclasses import dataclass\nfrom pathlib import Path\nfrom typing import Optional\n\nimport irsdk\n\n\ndef _get_appdata_dir() -> Path:\n    root = Path(os.getenv("APPDATA") or Path.home() / ".config")\n    path = root / "NishizumiTools"\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\n@dataclass\nclass StintState:\n    fuel_start: float\n    lap_start: int\n    lapdist_start: float\n    started_at: float\n\n\nclass FuelConsumptionMonitor:\n    WINDOW_WIDTH = 360\n    WINDOW_HEIGHT_COLLAPSED = 190\n    WINDOW_HEIGHT_EXPANDED = 310\n    LITER_TO_GALLON = 0.2641720524\n\n    def __init__(self) -> None:\n        self.ir = irsdk.IRSDK()\n\n        self.root = tk.Tk()\n        self.root.title("Fuel Consumption Monitor")\n        self.root.configure(bg="#0f1115")\n        self.root.overrideredirect(True)\n        self.root.attributes("-topmost", True)\n        self.root.attributes("-alpha", 0.92)\n        self._is_dragging = False\n\n        self._drag_offset_x = 0\n        self._drag_offset_y = 0\n\n        self._stint: Optional[StintState] = None\n        self._last_fuel: Optional[float] = None\n        self._last_lap: Optional[int] = None\n        self._lap_start_fuel: Optional[float] = None\n        self._last_lap_used: Optional[float] = None\n        self._pit_hold_until: float = 0.0\n        self._lap_consumptions: list[float] = []\n        self._locked_target: Optional[float] = None\n        self._last_on_pitroad: Optional[bool] = None\n        self._pit_overlay_until: float = 0.0\n        self._pit_overlay_value: Optional[float] = None\n        self._display_units: Optional[int] = None\n        self._unit_label = "L"\n        self._connected = False\n\n        self.refuel_threshold_l = 0.3\n        self.avg_min_progress = 0.05\n        self.anomaly_threshold = 0.3\n\n        self.target_var = tk.StringVar(value="2.50")\n        self.lock_target_var = tk.BooleanVar(value=False)\n        self.show_advanced_var = tk.BooleanVar(value=False)\n        self.advanced_toggle_text = tk.StringVar(value="I")\n\n        self._position_path = _get_appdata_dir() / "fuel_consumption_monitor.json"\n        self._apply_window_geometry(default_pos=(60, 60))\n\n        self._plus_one_target: Optional[float] = None\n        self._minus_one_target: Optional[float] = None\n        self._plus_one_laps: Optional[int] = None\n        self._minus_one_laps: Optional[int] = None\n\n        self._build_ui()\n\n        self.root.bind("<Escape>", self._ignore_escape)\n        self.root.bind("<ButtonPress-1>", self._start_move)\n        self.root.bind("<B1-Motion>", self._on_move)\n        self.root.bind("<ButtonRelease-1>", self._stop_move)\n        self.root.protocol("WM_DELETE_WINDOW", self._on_close)\n\n        self._update_loop()\n\n    def _build_ui(self) -> None:\n        top = tk.Frame(self.root, bg="#0f1115")\n        self.top_frame = top\n        top.pack(fill="x", padx=12, pady=(10, 4))\n\n        self.avg_label = tk.Label(\n            top,\n            text="--.-- L/Lap",\n            font=("Segoe UI", 20, "bold"),\n            fg="#d8f8d8",\n            bg="#0f1115",\n        )\n        self.avg_label.pack(side="left")\n\n        self.delta_label = tk.Label(\n            top,\n            text="(+0.00)",\n            font=("Segoe UI", 14, "bold"),\n            fg="#a0f0a0",\n            bg="#0f1115",\n            padx=8,\n        )\n        self.delta_label.pack(side="left")\n\n        bottom = tk.Frame(self.root, bg="#0f1115")\n        self.bottom_frame = bottom\n        bottom.pack(fill="x", padx=12, pady=(0, 6))\n\n        self.fuel_label = tk.Label(\n            bottom,\n            text="Fuel: --.-- L",\n            font=("Segoe UI", 12),\n            fg="#f2f2f2",\n            bg="#0f1115",\n        )\n        self.fuel_label.pack(anchor="w")\n\n        self.laps_label = tk.Label(\n            bottom,\n            text="Remaining: --.- laps",\n            font=("Segoe UI", 12),\n            fg="#f2f2f2",\n            bg="#0f1115",\n        )\n        self.laps_label.pack(anchor="w")\n\n        self.lastlap_label = tk.Label(\n            bottom,\n            text="Last lap: --.- L",\n            font=("Segoe UI", 12),\n            fg="#f2f2f2",\n            bg="#0f1115",\n        )\n        self.lastlap_label.pack(anchor="w")\n\n        self.stint_label = tk.Label(\n            bottom,\n            text="Stint: (C) --; (E) --",\n            font=("Segoe UI", 12),\n            fg="#d4d4d4",\n            bg="#0f1115",\n        )\n        self.stint_label.pack(anchor="w")\n\n        controls = tk.Frame(self.root, bg="#0f1115")\n        self.controls_frame = controls\n        controls.pack(fill="x", padx=12, pady=(0, 4))\n\n        button_column = tk.Frame(controls, bg="#0f1115")\n        button_column.pack(side="left", anchor="n", padx=(0, 8))\n\n        button_row = tk.Frame(button_column, bg="#0f1115")\n        button_row.pack(side="top")\n\n        tk.Button(\n            button_row,\n            text="R",\n            command=self._manual_reset,\n            font=("Segoe UI", 8),\n            bg="#1c2533",\n            fg="#e8e8e8",\n            relief="flat",\n            padx=2,\n            pady=0,\n            width=1,\n        ).pack(side="left", padx=(0, 4))\n\n        self.advanced_toggle_button = tk.Button(\n            button_row,\n            textvariable=self.advanced_toggle_text,\n            command=self._toggle_advanced_info,\n            font=("Segoe UI", 9),\n            bg="#1c2533",\n            fg="#e8e8e8",\n            relief="flat",\n            padx=6,\n            pady=2,\n            takefocus=False,\n        )\n        self.advanced_toggle_button.pack(side="left")\n\n        controls_body = tk.Frame(controls, bg="#0f1115")\n        controls_body.pack(side="left", fill="x", expand=True)\n\n        tk.Label(\n            controls_body,\n            text="Target L/Lap:",\n            font=("Segoe UI", 10),\n            fg="#c4c4c4",\n            bg="#0f1115",\n        ).pack(side="left")\n\n        self.target_entry = tk.Entry(\n            controls_body,\n            textvariable=self.target_var,\n            width=6,\n            font=("Segoe UI", 10),\n            justify="center",\n        )\n        self.target_entry.pack(side="left", padx=(6, 12))\n\n        tk.Checkbutton(\n            controls_body,\n            text="",\n            variable=self.lock_target_var,\n            command=self._toggle_target_lock,\n            font=("Segoe UI", 9),\n            fg="#c4c4c4",\n            bg="#0f1115",\n            activebackground="#0f1115",\n            activeforeground="#e8e8e8",\n            selectcolor="#1c2533",\n            relief="flat",\n        ).pack(side="left", padx=(0, 10))\n\n        self._apply_window_geometry()\n\n        self.advanced_frame = tk.Frame(self.root, bg="#0f1115")\n        self.advanced_info_label = tk.Label(\n            self.advanced_frame,\n            text="",\n            font=("Segoe UI", 11),\n            fg="#d4d4d4",\n            bg="#0f1115",\n            justify="left",\n            wraplength=320,\n        )\n        self.advanced_info_label.pack(anchor="w", pady=(0, 2))\n        advanced_buttons = tk.Frame(self.advanced_frame, bg="#0f1115")\n        advanced_buttons.pack(fill="x")\n\n        self.plus_one_button = tk.Button(\n            advanced_buttons,\n            text="+1 lap",\n            command=lambda: self._apply_advanced_target("plus"),\n            font=("Segoe UI", 11, "bold"),\n            bg="#1c2533",\n            fg="#e8e8e8",\n            relief="flat",\n            padx=14,\n            pady=4,\n        )\n        self.plus_one_button.pack(side="left", padx=(0, 12))\n\n        self.minus_one_button = tk.Button(\n            advanced_buttons,\n            text="-1lap",\n            command=lambda: self._apply_advanced_target("minus"),\n            font=("Segoe UI", 11, "bold"),\n            bg="#1c2533",\n            fg="#e8e8e8",\n            relief="flat",\n            padx=14,\n            pady=4,\n        )\n        self.minus_one_button.pack(side="left")\n\n        self.advanced_stint_label = tk.Label(\n            self.advanced_frame,\n            text="",\n            font=("Segoe UI", 9, "bold"),\n            fg="#d4d4d4",\n            bg="#0f1115",\n            justify="left",\n        )\n        self.advanced_stint_label.pack(anchor="w", pady=(2, 0))\n\n        self.status_label = tk.Label(\n            self.root,\n            text="Waiting for iRacing...",\n            font=("Segoe UI", 9),\n            fg="#8c8c8c",\n            bg="#0f1115",\n        )\n        self.status_label.pack(anchor="w", padx=12, pady=(0, 6))\n\n        self.pit_overlay_frame = tk.Frame(self.root, bg="#0f1115")\n        self.pit_overlay_label = tk.Label(\n            self.pit_overlay_frame,\n            text="Stint avg\\n--.-- L/Lap",\n            font=("Segoe UI", 20, "bold"),\n            fg="#6fe38f",\n            bg="#0f1115",\n            justify="center",\n        )\n        self.pit_overlay_label.pack(expand=True, fill="both", padx=12, pady=16)\n\n    def _set_display_units(self, display_units: Optional[int]) -> None:\n        if display_units not in (0, 1):\n            return\n        if self._display_units is None:\n            self._display_units = display_units\n            self._unit_label = "gal" if display_units == 0 else "L"\n            return\n        if display_units == self._display_units:\n            return\n        previous_units = self._display_units\n        target_liters = self._parse_target_with_units(previous_units)\n        self._display_units = display_units\n        self._unit_label = "gal" if display_units == 0 else "L"\n        if target_liters is not None:\n            target_display = self._from_liters(target_liters)\n            self.target_var.set(f"{target_display:.2f}")\n\n    def _from_liters(self, value: float) -> float:\n        if self._display_units == 0:\n            return value * self.LITER_TO_GALLON\n        return value\n\n    def _to_liters(self, value: float) -> float:\n        if self._display_units == 0:\n            return value / self.LITER_TO_GALLON\n        return value\n\n    def _set_standby_state(self, status_text: str) -> None:\n        unit = self._unit_label\n        self.avg_label.config(text=f"--.-- {unit}/Lap", fg="#c8c8c8")\n        self.delta_label.config(text="(--)", fg="#c8c8c8")\n        self.fuel_label.config(text=f"Fuel: --.-- {unit}")\n        self.laps_label.config(text="Remaining: --.- laps")\n        self.lastlap_label.config(text=f"Last lap: --.- {unit}")\n        self.stint_label.config(text="Stint: (C) --; (E) --", fg="#d4d4d4")\n        self.status_label.config(text=status_text)\n        self._hide_pit_overlay()\n\n    def _set_connection_state(self, connected: bool) -> None:\n        if connected == self._connected:\n            return\n        self._connected = connected\n        if not connected:\n            self._reset_stint()\n            self._last_on_pitroad = None\n            self._pit_overlay_until = 0.0\n            self._pit_overlay_value = None\n            self._set_standby_state("Waiting for iRacing connection...")\n\n    def _safe_float(self, key: str) -> Optional[float]:\n        try:\n            value = self.ir[key]\n        except Exception:\n            return None\n        if value is None:\n            return None\n        try:\n            return float(value)\n        except (TypeError, ValueError):\n            return None\n\n    def _safe_int(self, key: str) -> Optional[int]:\n        try:\n            value = self.ir[key]\n        except Exception:\n            return None\n        if value is None:\n            return None\n        try:\n            return int(value)\n        except (TypeError, ValueError):\n            return None\n\n    def _safe_bool(self, key: str) -> Optional[bool]:\n        try:\n            value = self.ir[key]\n        except Exception:\n            return None\n        if value is None:\n            return None\n        return bool(value)\n\n    def _manual_reset(self) -> None:\n        self._reset_stint()\n        self.status_label.config(text="Manual reset")\n\n    def _reset_stint(self) -> None:\n        self._stint = None\n        self._last_fuel = None\n        self._last_lap = None\n        self._lap_start_fuel = None\n        self._last_lap_used = None\n        self._lap_consumptions.clear()\n\n    def _update_stint(\n        self,\n        fuel_level: float,\n        lap: int,\n        lapdist: float,\n        session_flags: Optional[int],\n    ) -> None:\n        now = time.time()\n        if self._stint is None:\n            self._stint = StintState(\n                fuel_start=fuel_level,\n                lap_start=lap,\n                lapdist_start=lapdist,\n                started_at=now,\n            )\n            self._last_fuel = fuel_level\n            self._last_lap = lap\n            self._lap_start_fuel = fuel_level\n            self.status_label.config(text="Stint tracking")\n            return\n\n        if self._last_fuel is not None:\n            if fuel_level - self._last_fuel >= self.refuel_threshold_l:\n                self._pit_hold_until = now + 4.0\n                self._stint = StintState(\n                    fuel_start=fuel_level,\n                    lap_start=lap,\n                    lapdist_start=lapdist,\n                    started_at=now,\n                )\n                self._lap_start_fuel = fuel_level\n                self._last_lap_used = None\n                self.status_label.config(text="Refuel detected")\n\n        if self._last_lap is not None and lap is not None:\n            if lap > self._last_lap and self._lap_start_fuel is not None:\n                lap_progress = self._compute_progress(lap, lapdist)\n                lap_used = max(0.0, self._lap_start_fuel - fuel_level)\n                self._lap_start_fuel = fuel_level\n                if lap_progress is None or lap_progress < 1:\n                    self._last_lap_used = None\n                else:\n                    self._last_lap_used = lap_used\n                    if (\n                        self._last_lap_used > 0\n                        and not self._is_yellow_flag(session_flags)\n                        and not self._is_anomalous_lap(self._last_lap_used)\n                    ):\n                        self._lap_consumptions.append(self._last_lap_used)\n\n        self._last_fuel = fuel_level\n        self._last_lap = lap\n\n    def _compute_progress(self, lap: int, lapdist: float) -> Optional[float]:\n        if self._stint is None:\n            return None\n        progress = (lap - self._stint.lap_start) + (lapdist - self._stint.lapdist_start)\n        if progress < 0:\n            return None\n        return progress\n\n    def _parse_target(self) -> Optional[float]:\n        return self._parse_target_with_units(self._display_units)\n\n    def _parse_target_with_units(self, display_units: Optional[int]) -> Optional[float]:\n        try:\n            value = float(self.target_var.get().strip())\n        except ValueError:\n            return None\n        if display_units == 0:\n            return value / self.LITER_TO_GALLON\n        return value\n\n    def _toggle_target_lock(self) -> None:\n        if self.lock_target_var.get():\n            target = self._parse_target()\n            if target is not None:\n                self._locked_target = target\n                self.target_entry.configure(state="disabled")\n                self.status_label.config(text="Target locked")\n            else:\n                self.lock_target_var.set(False)\n        else:\n            self._locked_target = None\n            self.target_entry.configure(state="normal")\n            self.status_label.config(text="Target unlocked")\n\n    def _toggle_advanced_info(self) -> None:\n        show_advanced = not self.show_advanced_var.get()\n        self.show_advanced_var.set(show_advanced)\n        if show_advanced:\n            self.advanced_frame.pack(fill="x", padx=12, pady=(0, 4))\n            self._apply_window_geometry()\n        else:\n            self.advanced_frame.pack_forget()\n            self._apply_window_geometry()\n        self.advanced_toggle_text.set("I")\n\n    def _apply_advanced_target(self, mode: str) -> None:\n        if mode == "plus":\n            target = self._plus_one_target\n        else:\n            target = self._minus_one_target\n        if target is None:\n            return\n        self.target_var.set(f"{self._from_liters(target):.2f}")\n        if self.lock_target_var.get():\n            self._locked_target = target\n        self.status_label.config(text="Target updated from advanced")\n\n    def _is_yellow_flag(self, session_flags: Optional[int]) -> bool:\n        if session_flags is None:\n            return False\n        flags = getattr(irsdk, "Flags", None)\n        if flags is None:\n            return False\n        for attr in ("YELLOW", "CAUTION", "YELLOW_WAVING", "CAUTION_WAVING"):\n            mask = getattr(flags, attr, None)\n            if mask is not None and session_flags & mask:\n                return True\n        return False\n\n    def _is_anomalous_lap(self, lap_used: float) -> bool:\n        if lap_used <= 0:\n            return True\n        if len(self._lap_consumptions) < 3:\n            return False\n        avg = sum(self._lap_consumptions) / len(self._lap_consumptions)\n        if avg <= 0:\n            return False\n        deviation = abs(lap_used - avg) / avg\n        return deviation >= self.anomaly_threshold\n\n    def _filtered_average(self, fallback: Optional[float]) -> Optional[float]:\n        if fallback is None:\n            if self._lap_consumptions:\n                return sum(self._lap_consumptions) / len(self._lap_consumptions)\n            return None\n        if self._lap_consumptions:\n            lap_total = sum(self._lap_consumptions)\n            return (lap_total + fallback) / (len(self._lap_consumptions) + 1)\n        return fallback\n\n    def _stint_average(self, fallback: Optional[float]) -> Optional[float]:\n        if self._lap_consumptions:\n            return sum(self._lap_consumptions) / len(self._lap_consumptions)\n        return fallback\n\n    def _show_pit_overlay(self, avg_value: Optional[float]) -> None:\n        if avg_value is None:\n            text = f"Stint avg\\n--.-- {self._unit_label}/Lap"\n        else:\n            text = f"Stint avg\\n{self._from_liters(avg_value):.2f} {self._unit_label}/Lap"\n        self.pit_overlay_label.config(text=text)\n        if not self.pit_overlay_frame.winfo_ismapped():\n            for frame in (\n                self.top_frame,\n                self.bottom_frame,\n                self.controls_frame,\n                self.advanced_frame,\n                self.status_label,\n            ):\n                frame.pack_forget()\n            self.pit_overlay_frame.pack(expand=True, fill="both")\n\n    def _hide_pit_overlay(self) -> None:\n        if not self.pit_overlay_frame.winfo_ismapped():\n            return\n        self.pit_overlay_frame.pack_forget()\n        self.top_frame.pack(fill="x", padx=12, pady=(10, 4))\n        self.bottom_frame.pack(fill="x", padx=12, pady=(0, 6))\n        self.controls_frame.pack(fill="x", padx=12, pady=(0, 4))\n        if self.show_advanced_var.get():\n            self.advanced_frame.pack(fill="x", padx=12, pady=(0, 4))\n        self.status_label.pack(anchor="w", padx=12, pady=(0, 6))\n\n    def _update_loop(self) -> None:\n        if not getattr(self.ir, "is_initialized", False):\n            if not self.ir.startup():\n                self._set_connection_state(False)\n                self.root.after(500, self._update_loop)\n                return\n        self._set_connection_state(True)\n\n        self._set_display_units(self._safe_int("DisplayUnits"))\n        fuel_level = self._safe_float("FuelLevel")\n        lapdist = self._safe_float("LapDistPct")\n        lap = self._safe_int("Lap")\n        is_on_track = self._safe_bool("IsOnTrack")\n        session_flags = self._safe_int("SessionFlags")\n        on_pit_road = self._safe_bool("OnPitRoad")\n\n        if fuel_level is None or lap is None or lapdist is None or not is_on_track:\n            self._reset_stint()\n            self._set_standby_state("Waiting for telemetry...")\n            self.root.after(200, self._update_loop)\n            return\n\n        self._update_stint(fuel_level, lap, lapdist, session_flags)\n\n        progress = self._compute_progress(lap, lapdist)\n        avg_per_lap: Optional[float] = None\n        if progress is not None and progress >= self.avg_min_progress:\n            assert self._stint is not None\n            fuel_used = max(0.0, self._stint.fuel_start - fuel_level)\n            if progress > 0:\n                avg_per_lap = fuel_used / progress\n\n        avg_per_lap = self._filtered_average(avg_per_lap)\n        target = self._locked_target if self.lock_target_var.get() else self._parse_target()\n\n        if avg_per_lap is None:\n            self.avg_label.config(\n                text=f"--.-- {self._unit_label}/Lap",\n                fg="#c8c8c8",\n            )\n            self.delta_label.config(text="(--)", fg="#c8c8c8")\n        else:\n            display_avg = self._from_liters(avg_per_lap)\n            display_target = self._from_liters(target) if target is not None else None\n            delta = display_avg - display_target if display_target is not None else None\n            within_target = target is not None and avg_per_lap <= target\n            avg_color = "#6fe38f" if within_target else "#ff6b6b"\n            delta_color = avg_color\n            self.avg_label.config(\n                text=f"{display_avg:.2f} {self._unit_label}/Lap",\n                fg=avg_color,\n            )\n            if delta is None:\n                self.delta_label.config(text="(--) ", fg="#c8c8c8")\n            else:\n                self.delta_label.config(text=f"({delta:+.2f})", fg=delta_color)\n\n        self.fuel_label.config(\n            text=f"Fuel: {self._from_liters(fuel_level):.2f} {self._unit_label}"\n        )\n\n        if avg_per_lap and avg_per_lap > 0:\n            remaining = fuel_level / avg_per_lap\n            self.laps_label.config(text=f"Remaining: {remaining:.1f} laps")\n        else:\n            self.laps_label.config(text="Remaining: --.- laps")\n\n        stint_text = "Stint: (C) --; (E) --"\n        stint_color = "#d4d4d4"\n        planned_laps = None\n        base_laps = None\n\n        if avg_per_lap and avg_per_lap > 0:\n            remaining = fuel_level / avg_per_lap\n            base_laps = max(0, math.floor(remaining))\n            if target is not None and target > 0:\n                planned_laps = math.floor(fuel_level / target)\n                if base_laps >= planned_laps + 1:\n                    stint_color = "#b784ff"\n                elif base_laps <= planned_laps - 1:\n                    stint_color = "#ff6b6b"\n                else:\n                    stint_color = "#6fe38f"\n            if planned_laps is None:\n                stint_text = f"Stint: (C) --; (E) {base_laps}"\n            else:\n                stint_text = f"Stint: (C) {planned_laps}; (E) {base_laps}"\n\n        self.stint_label.config(text=stint_text, fg=stint_color)\n\n        if self.show_advanced_var.get():\n            if avg_per_lap and avg_per_lap > 0:\n                self._plus_one_laps = base_laps + 1\n                self._minus_one_laps = max(base_laps - 1, 1) if base_laps >= 1 else None\n                self._plus_one_target = (\n                    fuel_level / self._plus_one_laps if self._plus_one_laps else None\n                )\n                self._minus_one_target = (\n                    fuel_level / self._minus_one_laps\n                    if self._minus_one_laps\n                    else None\n                )\n                savings_text = ""\n                if planned_laps is not None and planned_laps >= 1 and target is not None:\n                    gain_lap_target = fuel_level / (planned_laps + 1)\n                    save_per_lap = max(0.0, target - gain_lap_target)\n                    loss_lap_text = None\n                    if planned_laps >= 2:\n                        lose_lap_target = fuel_level / (planned_laps - 1)\n                        spend_more = max(0.0, lose_lap_target - target)\n                        loss_lap_text = (\n                            f"Use {self._from_liters(spend_more):.2f} {self._unit_label}/lap more = -1 lap"\n                        )\n                    savings_lines = [\n                        f"Save {self._from_liters(save_per_lap):.2f} {self._unit_label}/lap = +1 lap"\n                    ]\n                    if loss_lap_text:\n                        savings_lines.append(loss_lap_text)\n                    savings_text = "\\n".join(savings_lines)\n                self.advanced_info_label.config(text=savings_text)\n                self.advanced_stint_label.config(text="", fg=stint_color)\n                if self._plus_one_target is not None:\n                    self.plus_one_button.config(\n                        text="+1 lap",\n                        state="normal",\n                    )\n                else:\n                    self.plus_one_button.config(text="+1 lap", state="disabled")\n                if self._minus_one_target is not None:\n                    self.minus_one_button.config(\n                        text="-1lap",\n                        state="normal",\n                    )\n                else:\n                    self.minus_one_button.config(text="-1lap", state="disabled")\n            else:\n                self._plus_one_target = None\n                self._minus_one_target = None\n                self._plus_one_laps = None\n                self._minus_one_laps = None\n                self.advanced_info_label.config(\n                    text="Waiting for valid laps to estimate the stint..."\n                )\n                self.advanced_stint_label.config(text="", fg="#d4d4d4")\n                self.plus_one_button.config(text="+1 lap", state="disabled")\n                self.minus_one_button.config(text="-1lap", state="disabled")\n\n        if self._last_lap_used is not None:\n            self.lastlap_label.config(\n                text=f"Last lap: {self._from_liters(self._last_lap_used):.2f} {self._unit_label}"\n            )\n        else:\n            self.lastlap_label.config(text=f"Last lap: --.- {self._unit_label}")\n\n        now = time.time()\n        if on_pit_road and not self._last_on_pitroad:\n            self._pit_overlay_value = self._stint_average(avg_per_lap)\n            self._pit_overlay_until = now + 10.0\n\n        self._last_on_pitroad = on_pit_road\n\n        if now < self._pit_hold_until:\n            self.status_label.config(text="PIT")\n        elif self._stint is not None:\n            self.status_label.config(text="Stint tracking")\n\n        if now < self._pit_overlay_until:\n            self._show_pit_overlay(self._pit_overlay_value)\n        else:\n            self._hide_pit_overlay()\n\n        self.root.after(100, self._update_loop)\n\n    def _start_move(self, event: tk.Event) -> None:\n        if self.lock_target_var.get():\n            return\n        if not self._is_drag_allowed(event.widget):\n            return\n        self._is_dragging = True\n        self._drag_offset_x = event.x_root - self.root.winfo_x()\n        self._drag_offset_y = event.y_root - self.root.winfo_y()\n\n    def _on_move(self, event: tk.Event) -> None:\n        if not self._is_dragging:\n            return\n        x = event.x_root - self._drag_offset_x\n        y = event.y_root - self._drag_offset_y\n        self.root.geometry(f"+{x}+{y}")\n\n    def _stop_move(self, event: tk.Event) -> None:\n        if not self._is_dragging:\n            return\n        self._is_dragging = False\n        self._save_window_position()\n\n    def _on_close(self, event: tk.Event | None = None) -> None:\n        self._save_window_position()\n        try:\n            self.ir.shutdown()\n        except Exception:\n            pass\n        self.root.destroy()\n\n    def _ignore_escape(self, event: tk.Event) -> str:\n        return "break"\n\n    def _is_drag_allowed(self, widget: tk.Widget) -> bool:\n        if isinstance(widget, (tk.Entry, tk.Button, tk.Checkbutton)):\n            return False\n        return True\n\n    def _apply_window_geometry(self, default_pos: tuple[int, int] | None = None) -> None:\n        width = self._get_window_width()\n        height = (\n            self.WINDOW_HEIGHT_EXPANDED\n            if self.show_advanced_var.get()\n            else self.WINDOW_HEIGHT_COLLAPSED\n        )\n        position = self._load_window_position()\n        if position is None and default_pos is not None:\n            position = default_pos\n        if position is None:\n            self.root.geometry(f"{width}x{height}")\n            return\n        x, y = position\n        self.root.geometry(f"{width}x{height}+{x}+{y}")\n\n    def _get_window_width(self) -> int:\n        top_frame = getattr(self, "top_frame", None)\n        if top_frame is None:\n            return self.WINDOW_WIDTH\n        self.root.update_idletasks()\n        content_width = top_frame.winfo_reqwidth() + 24\n        return max(content_width, 1)\n\n    def _load_window_position(self) -> Optional[tuple[int, int]]:\n        try:\n            data = json.loads(self._position_path.read_text(encoding="utf-8"))\n        except (OSError, json.JSONDecodeError):\n            return None\n        x = data.get("x")\n        y = data.get("y")\n        if isinstance(x, int) and isinstance(y, int):\n            return x, y\n        return None\n\n    def _save_window_position(self) -> None:\n        try:\n            self._position_path.write_text(\n                json.dumps({"x": self.root.winfo_x(), "y": self.root.winfo_y()}),\n                encoding="utf-8",\n            )\n        except OSError:\n            pass\n\n\ndef main() -> int:\n    try:\n        FuelConsumptionMonitor()\n        tk.mainloop()\n    except KeyboardInterrupt:\n        return 0\n    return 0\n\n\nif __name__ == "__main__":\n    sys.exit(main())\n',
    'pittime': '#!/usr/bin/env python3\n"""Standalone Tkinter overlay for pit-stop loss and rejoin safety estimation."""\n\nfrom __future__ import annotations\n\nimport math\nimport json\nimport os\nfrom pathlib import Path\nimport tkinter as tk\nfrom typing import Dict, List, Optional, Tuple\n\nimport irsdk\n\nUPDATE_MS = 16\nDEFAULT_LAP_TIME_S = 90.0\nGREEN_GAP_S = 5.0\nYELLOW_GAP_S = 1.5\n\n\ndef _get_appdata_dir() -> Path:\n    root = Path(os.getenv("APPDATA") or Path.home() / ".config")\n    path = root / "NishizumiTools"\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\nRATE_FILE = _get_appdata_dir() / "nishizumi_pittime_fuel_rates.json"\n\n\nclass PitStopOverlay:\n    BG = "#0f1115"\n    PANEL = "#171a21"\n    PANEL_ALT = "#1d2230"\n    CARD = "#22293a"\n    CARD_BORDER = "#3a4358"\n    TEXT = "#f2f2f2"\n    MUTED = "#9aa4b2"\n    ENTRY_BG = "#101826"\n    ENTRY_BORDER = "#2b3647"\n\n    def __init__(self) -> None:\n        self.ir = irsdk.IRSDK()\n\n        self.root = tk.Tk()\n        self.root.title("Pit Window Overlay")\n        self.root.geometry("500x440")\n        self.root.configure(bg=self.BG)\n        self.root.overrideredirect(True)\n        self.root.attributes("-topmost", True)\n        self.root.attributes("-alpha", 0.95)\n\n        self._drag_offset_x = 0\n        self._drag_offset_y = 0\n\n        self.base_loss_var = tk.StringVar(value="20.0")\n        self.tire_loss_var = tk.StringVar(value="0.0")\n        self.fuel_rate_var = tk.StringVar(value="2.2")\n        self.custom_fuel_max_var = tk.StringVar(value="")\n        self.use_custom_fuel_max_var = tk.BooleanVar(value=False)\n        self.lock_inputs_var = tk.BooleanVar(value=False)\n        self.minimal_mode_var = tk.BooleanVar(value=False)\n\n        self.connection_var = tk.StringVar(value="Connecting to iRacing...")\n        self.car_var = tk.StringVar(value="Car: --")\n        self.fuel_state_var = tk.StringVar(value="Fuel: -- / -- L")\n        self.fuel_time_var = tk.StringVar(value="Fuel time: -- s")\n        self.total_time_var = tk.StringVar(value="Total pit time loss: -- s")\n        self.window_var = tk.StringVar(value="Awaiting telemetry")\n        self.status_var = tk.StringVar(value="Status: --")\n\n        self.profile_data = self._load_profiles()\n        self.active_car_id: Optional[str] = None\n        self.active_car_name: Optional[str] = None\n        self.active_track_id: Optional[str] = None\n        self.active_track_name: Optional[str] = None\n        self._last_fuel_level: Optional[float] = None\n        self._last_tick_s: Optional[float] = None\n        self._is_fueling = False\n        self._fueling_samples: List[float] = []\n        self._fuel_rate_autofilled = False\n        self._editable_entries: List[tk.Entry] = []\n        self._mousewheel_bound = False\n\n        self._build_ui()\n\n    def _build_ui(self) -> None:\n        self.title_bar = tk.Frame(self.root, bg=self.BG)\n        self.title_bar.pack(fill="x", padx=10, pady=(8, 4))\n\n        title_stack = tk.Frame(self.title_bar, bg=self.BG)\n        title_stack.pack(side="left", fill="x", expand=True)\n        tk.Label(\n            title_stack,\n            text="Pit Stop Overlay",\n            font=("Segoe UI", 13, "bold"),\n            fg="#d8f8d8",\n            bg=self.BG,\n        ).pack(anchor="w")\n        tk.Label(\n            title_stack,\n            text="Loss + rejoin safety estimator",\n            font=("Segoe UI", 9),\n            fg=self.MUTED,\n            bg=self.BG,\n        ).pack(anchor="w")\n\n        self.scroll_canvas = tk.Canvas(\n            self.root,\n            bg=self.BG,\n            highlightthickness=0,\n            bd=0,\n        )\n        self.scrollbar = tk.Scrollbar(\n            self.root,\n            orient="vertical",\n            command=self.scroll_canvas.yview,\n            troughcolor=self.BG,\n            bg="#253247",\n            activebackground="#334766",\n        )\n        self.scroll_canvas.configure(yscrollcommand=self.scrollbar.set)\n        self.scroll_canvas.pack(side="left", fill="both", expand=True)\n        self.scrollbar.pack(side="right", fill="y")\n\n        self.main_frame = tk.Frame(self.scroll_canvas, bg=self.BG)\n        self._canvas_window = self.scroll_canvas.create_window((0, 0), window=self.main_frame, anchor="nw")\n        self.main_frame.bind("<Configure>", self._on_main_frame_configure)\n        self.scroll_canvas.bind("<Configure>", self._on_canvas_configure)\n        self.scroll_canvas.bind("<Enter>", self._bind_mousewheel)\n        self.scroll_canvas.bind("<Leave>", self._unbind_mousewheel)\n\n        self.inputs_frame = tk.LabelFrame(\n            self.main_frame,\n            text=" Pit loss setup ",\n            font=("Segoe UI", 10, "bold"),\n            fg=self.TEXT,\n            bg=self.PANEL,\n            bd=0,\n            padx=10,\n            pady=10,\n        )\n        self.inputs_frame.pack(fill="x")\n\n        self._editable_entries.append(\n            self._row_entry(self.inputs_frame, "Base pit loss (in + out, no service) [s]", self.base_loss_var, 0)\n        )\n        self._editable_entries.append(\n            self._row_entry(self.inputs_frame, "Tire-change loss [s]", self.tire_loss_var, 1)\n        )\n        self._row_entry(self.inputs_frame, "Fuel rate [L/s] (auto-learned)", self.fuel_rate_var, 2, editable=False)\n\n        custom_max_check = tk.Checkbutton(\n            self.inputs_frame,\n            text="Use custom fuel tank max [L]",\n            variable=self.use_custom_fuel_max_var,\n            font=("Segoe UI", 10),\n            fg=self.TEXT,\n            bg=self.PANEL,\n            activebackground=self.PANEL,\n            activeforeground=self.TEXT,\n            selectcolor=self.BG,\n        )\n        custom_max_check.grid(row=3, column=0, sticky="w", padx=(0, 8), pady=(6, 2))\n        custom_max_entry = self._row_entry(self.inputs_frame, "Custom fuel max [L]", self.custom_fuel_max_var, 4)\n        self._editable_entries.append(custom_max_entry)\n\n        lock_check = tk.Checkbutton(\n            self.inputs_frame,\n            text="Lock typed inputs (read-only)",\n            variable=self.lock_inputs_var,\n            command=self._apply_lock_state,\n            font=("Segoe UI", 10),\n            fg=self.TEXT,\n            bg=self.PANEL,\n            activebackground=self.PANEL,\n            activeforeground=self.TEXT,\n            selectcolor=self.BG,\n        )\n        lock_check.grid(row=5, column=0, columnspan=2, sticky="w", pady=(8, 2))\n\n        minimal_mode_check = tk.Checkbutton(\n            self.inputs_frame,\n            text="Race minimal mode (only pit rejoin safety bar)",\n            variable=self.minimal_mode_var,\n            command=self._apply_minimal_mode,\n            font=("Segoe UI", 10),\n            fg=self.TEXT,\n            bg=self.PANEL,\n            activebackground=self.PANEL,\n            activeforeground=self.TEXT,\n            selectcolor=self.BG,\n        )\n        minimal_mode_check.grid(row=6, column=0, columnspan=2, sticky="w", pady=(2, 2))\n\n        self.connection_label = tk.Label(\n            self.main_frame,\n            textvariable=self.connection_var,\n            fg=self.MUTED,\n            bg=self.BG,\n            font=("Segoe UI", 9),\n        )\n        self.connection_label.pack(anchor="w", pady=(8, 2))\n        self.car_label = tk.Label(\n            self.main_frame,\n            textvariable=self.car_var,\n            fg=self.MUTED,\n            bg=self.BG,\n            font=("Segoe UI", 9),\n        )\n        self.car_label.pack(anchor="w", pady=(0, 4))\n        self.top_separator = tk.Frame(self.main_frame, bg="#2b3447", height=1)\n        self.top_separator.pack(fill="x", pady=4)\n\n        self.metrics_frame = tk.LabelFrame(\n            self.main_frame,\n            text=" Live calculations ",\n            font=("Segoe UI", 10, "bold"),\n            fg=self.TEXT,\n            bg=self.PANEL,\n            bd=0,\n            padx=10,\n            pady=10,\n        )\n        self.metrics_frame.pack(fill="x", pady=(6, 8))\n\n        tk.Label(self.metrics_frame, textvariable=self.fuel_state_var, font=("Segoe UI", 10), fg=self.TEXT, bg=self.PANEL).pack(anchor="w")\n        tk.Label(self.metrics_frame, textvariable=self.fuel_time_var, font=("Segoe UI", 10), fg=self.TEXT, bg=self.PANEL).pack(anchor="w", pady=(2, 0))\n        tk.Label(self.metrics_frame, textvariable=self.total_time_var, font=("Segoe UI", 11, "bold"), fg="#d8f8d8", bg=self.PANEL).pack(anchor="w", pady=(5, 0))\n\n        self.status_frame = tk.LabelFrame(\n            self.main_frame,\n            text=" Pit rejoin safety ",\n            font=("Segoe UI", 10, "bold"),\n            fg=self.TEXT,\n            bg=self.PANEL_ALT,\n            bd=0,\n            padx=10,\n            pady=10,\n        )\n        self.status_frame.pack(fill="both", expand=True)\n\n        self.minimal_header = tk.Frame(self.status_frame, bg=self.PANEL_ALT)\n\n        self.minimal_title_label = tk.Label(\n            self.minimal_header,\n            text="Pit rejoin safety",\n            font=("Segoe UI", 10, "bold"),\n            fg=self.MUTED,\n            bg=self.PANEL_ALT,\n        )\n        self.minimal_title_label.pack(side="left", anchor="w")\n\n        self.restore_button = tk.Button(\n            self.minimal_header,\n            text="⤢",\n            command=self._exit_minimal_mode,\n            font=("Segoe UI Symbol", 11, "bold"),\n            bg="#242c3c",\n            fg=self.TEXT,\n            activebackground="#36415a",\n            activeforeground="white",\n            relief="flat",\n            bd=0,\n            padx=8,\n            pady=3,\n            takefocus=False,\n            cursor="hand2",\n            width=2,\n        )\n        self.restore_button.pack(side="right")\n\n        self.score_label = tk.Label(\n            self.status_frame,\n            textvariable=self.window_var,\n            font=("Segoe UI", 28, "bold"),\n            bg=self.CARD,\n            fg="white",\n            padx=12,\n            pady=10,\n            relief="flat",\n            bd=0,\n            highlightthickness=1,\n            highlightbackground=self.CARD_BORDER,\n        )\n        self.score_label.pack(fill="x")\n\n        self.status_details_label = tk.Label(\n            self.status_frame,\n            textvariable=self.status_var,\n            font=("Segoe UI", 11),\n            wraplength=430,\n            justify="left",\n            fg=self.TEXT,\n            bg=self.PANEL_ALT,\n        )\n        self.status_details_label.pack(anchor="w", pady=(10, 4))\n\n        self.legend_label = tk.Label(\n            self.status_frame,\n            text=(\n                "Legend: GREEN >= 5.0 s free front and rear, "\n                "YELLOW >= 1.5 s, RED < 1.5 s."\n            ),\n            fg=self.MUTED,\n            bg=self.PANEL_ALT,\n            wraplength=430,\n            justify="left",\n        )\n        self.legend_label.pack(anchor="w")\n\n        self.root.bind("<ButtonPress-1>", self._start_move)\n        self.root.bind("<B1-Motion>", self._on_move)\n\n    def _on_main_frame_configure(self, _: tk.Event) -> None:\n        self.scroll_canvas.configure(scrollregion=self.scroll_canvas.bbox("all"))\n\n    def _on_canvas_configure(self, event: tk.Event) -> None:\n        self.scroll_canvas.itemconfigure(self._canvas_window, width=event.width)\n\n    def _bind_mousewheel(self, _: tk.Event) -> None:\n        if self._mousewheel_bound:\n            return\n        self.root.bind_all("<MouseWheel>", self._on_mousewheel)\n        self.root.bind_all("<Button-4>", self._on_mousewheel)\n        self.root.bind_all("<Button-5>", self._on_mousewheel)\n        self._mousewheel_bound = True\n\n    def _unbind_mousewheel(self, _: tk.Event) -> None:\n        if not self._mousewheel_bound:\n            return\n        self.root.unbind_all("<MouseWheel>")\n        self.root.unbind_all("<Button-4>")\n        self.root.unbind_all("<Button-5>")\n        self._mousewheel_bound = False\n\n    def _on_mousewheel(self, event: tk.Event) -> None:\n        if not self.scroll_canvas.winfo_exists():\n            return\n        if hasattr(event, "delta") and event.delta:\n            direction = -1 if event.delta > 0 else 1\n            self.scroll_canvas.yview_scroll(direction, "units")\n            return\n        if getattr(event, "num", None) == 4:\n            self.scroll_canvas.yview_scroll(-1, "units")\n        elif getattr(event, "num", None) == 5:\n            self.scroll_canvas.yview_scroll(1, "units")\n\n    def _exit_minimal_mode(self) -> None:\n        self.minimal_mode_var.set(False)\n        self._apply_minimal_mode()\n\n    def _apply_minimal_mode(self) -> None:\n        if self.minimal_mode_var.get():\n            self.title_bar.pack_forget()\n            self.inputs_frame.pack_forget()\n            self.connection_label.pack_forget()\n            self.car_label.pack_forget()\n            self.top_separator.pack_forget()\n            self.metrics_frame.pack_forget()\n            self.status_details_label.pack_forget()\n            self.legend_label.pack_forget()\n            self.scrollbar.pack_forget()\n            self.minimal_header.pack(fill="x", pady=(0, 8), before=self.score_label)\n            self.status_frame.configure(text="", padx=10, pady=10)\n            self.status_frame.pack_configure(fill="both", expand=True, pady=0)\n            self.score_label.configure(\n                font=("Segoe UI", 24, "bold"),\n                padx=16,\n                pady=12,\n                anchor="center",\n            )\n            self.score_label.pack_configure(fill="both", expand=True, pady=0)\n            self.root.geometry("336x128")\n            return\n\n        self.title_bar.pack(fill="x", padx=10, pady=(8, 4), before=self.scroll_canvas)\n        self.minimal_header.pack_forget()\n        self.scrollbar.pack(side="right", fill="y")\n        self.inputs_frame.pack(fill="x")\n        self.connection_label.pack(anchor="w", pady=(8, 2))\n        self.car_label.pack(anchor="w", pady=(0, 4))\n        self.top_separator.pack(fill="x", pady=4)\n        self.metrics_frame.pack(fill="x", pady=(6, 8))\n        self.status_frame.configure(text=" Pit rejoin safety ", padx=10, pady=10)\n        self.status_frame.pack_configure(fill="both", expand=True)\n        self.score_label.configure(\n            font=("Segoe UI", 28, "bold"),\n            padx=12,\n            pady=10,\n            anchor="w",\n        )\n        self.score_label.pack_configure(fill="x", expand=False, pady=0)\n        self.status_details_label.pack(anchor="w", pady=(10, 4))\n        self.legend_label.pack(anchor="w")\n        self.root.geometry("500x440")\n\n    def _row_entry(\n        self,\n        parent: tk.Widget,\n        label: str,\n        var: tk.StringVar,\n        row: int,\n        editable: bool = True,\n    ) -> tk.Entry:\n        tk.Label(\n            parent,\n            text=label,\n            font=("Segoe UI", 10),\n            fg=self.TEXT,\n            bg=self.PANEL,\n        ).grid(row=row, column=0, sticky="w", padx=(0, 8), pady=4)\n        state = "normal" if editable else "readonly"\n        entry = tk.Entry(\n            parent,\n            textvariable=var,\n            width=12,\n            state=state,\n            font=("Segoe UI", 10),\n            justify="center",\n            bg=self.ENTRY_BG,\n            fg=self.TEXT,\n            readonlybackground=self.ENTRY_BG,\n            disabledforeground="#7f8ea3",\n            insertbackground=self.TEXT,\n            relief="flat",\n            highlightthickness=1,\n            highlightbackground=self.ENTRY_BORDER,\n            highlightcolor="#3c79ff",\n        )\n        entry.grid(row=row, column=1, sticky="e", pady=4)\n        parent.grid_columnconfigure(0, weight=1)\n        return entry\n\n    def _start_move(self, event: tk.Event) -> None:\n        self._drag_offset_x = event.x_root - self.root.winfo_x()\n        self._drag_offset_y = event.y_root - self.root.winfo_y()\n\n    def _on_move(self, event: tk.Event) -> None:\n        x = event.x_root - self._drag_offset_x\n        y = event.y_root - self._drag_offset_y\n        self.root.geometry(f"+{x}+{y}")\n\n    @staticmethod\n    def _safe_float(value: str, default: float = 0.0, minimum: float = 0.0) -> float:\n        try:\n            parsed = float(value)\n        except (TypeError, ValueError):\n            return default\n        if math.isnan(parsed) or math.isinf(parsed):\n            return default\n        return max(minimum, parsed)\n\n    @staticmethod\n    def _safe_str(value: object, default: str = "") -> str:\n        if value is None:\n            return default\n        text = str(value).strip()\n        return text or default\n\n    def _read_telemetry(self, name: str, default: Optional[float] = None):\n        try:\n            return self.ir[name]\n        except Exception:\n            return default\n\n    def _driver_fuel_max_liters(self) -> Optional[float]:\n        try:\n            driver_info = self.ir["DriverInfo"]\n            if isinstance(driver_info, dict):\n                value = driver_info.get("DriverCarFuelMaxLtr")\n                if isinstance(value, (float, int)) and value > 0:\n                    return float(value)\n        except Exception:\n            return None\n        return None\n\n    def _driver_identity(self) -> Tuple[Optional[str], Optional[str]]:\n        try:\n            driver_info = self.ir["DriverInfo"]\n        except Exception:\n            return None, None\n\n        if not isinstance(driver_info, dict):\n            return None, None\n\n        driver_car_idx = driver_info.get("DriverCarIdx")\n        drivers = driver_info.get("Drivers")\n        if not isinstance(drivers, list):\n            return None, None\n\n        for entry in drivers:\n            if not isinstance(entry, dict):\n                continue\n            if entry.get("CarIdx") != driver_car_idx:\n                continue\n\n            car_name = self._safe_str(\n                entry.get("CarScreenNameShort")\n                or entry.get("CarScreenName")\n                or entry.get("CarPath")\n                or entry.get("UserName"),\n                default="Unknown car",\n            )\n            car_id = self._safe_str(\n                entry.get("CarPath")\n                or entry.get("CarClassShortName")\n                or str(driver_car_idx),\n                default="unknown_car",\n            )\n            return car_id, car_name\n\n        return None, None\n\n    def _track_identity(self) -> Tuple[Optional[str], Optional[str]]:\n        try:\n            weekend_info = self.ir["WeekendInfo"]\n        except Exception:\n            return None, None\n\n        if not isinstance(weekend_info, dict):\n            return None, None\n\n        track_name = self._safe_str(\n            weekend_info.get("TrackDisplayName")\n            or weekend_info.get("TrackName")\n            or weekend_info.get("TrackID"),\n            default="Unknown track",\n        )\n        track_id = self._safe_str(\n            weekend_info.get("TrackName")\n            or weekend_info.get("TrackDisplayShortName")\n            or weekend_info.get("TrackID"),\n            default="unknown_track",\n        )\n        return track_id, track_name\n\n    def _profile_key(self, car_id: Optional[str], track_id: Optional[str]) -> Optional[str]:\n        if not car_id or not track_id:\n            return None\n        return f"{car_id}::{track_id}"\n\n    def _load_profiles(self) -> Dict[str, Dict[str, float]]:\n        if not RATE_FILE.exists():\n            return {}\n        try:\n            raw = json.loads(RATE_FILE.read_text(encoding="utf-8"))\n        except Exception:\n            return {}\n        if not isinstance(raw, dict):\n            return {}\n        profiles: Dict[str, Dict[str, float]] = {}\n        for profile_key, data in raw.items():\n            if isinstance(data, dict):\n                normalized: Dict[str, float] = {}\n                for field in ("fuel_rate", "base_loss", "tire_loss", "custom_fuel_max"):\n                    value = data.get(field)\n                    if value is None:\n                        continue\n                    try:\n                        parsed = float(value)\n                    except (TypeError, ValueError):\n                        continue\n                    if parsed < 0:\n                        continue\n                    normalized[field] = parsed\n                if normalized:\n                    profiles[str(profile_key)] = normalized\n            else:\n                # Backward compatibility with old {car_id: fuel_rate} format.\n                try:\n                    parsed = float(data)\n                except (TypeError, ValueError):\n                    continue\n                if parsed > 0:\n                    profiles[f"{profile_key}::unknown_track"] = {"fuel_rate": parsed}\n        return profiles\n\n    def _save_profiles(self) -> None:\n        payload: Dict[str, Dict[str, float]] = {}\n        for profile_key, values in sorted(self.profile_data.items()):\n            row: Dict[str, float] = {}\n            for field in ("fuel_rate", "base_loss", "tire_loss", "custom_fuel_max"):\n                value = values.get(field)\n                if isinstance(value, (float, int)) and value >= 0:\n                    row[field] = round(float(value), 4)\n            if row:\n                payload[profile_key] = row\n        try:\n            RATE_FILE.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")\n        except Exception:\n            pass\n\n    def _apply_profile_if_known(self, car_id: Optional[str], track_id: Optional[str]) -> None:\n        profile_key = self._profile_key(car_id, track_id)\n        if not profile_key:\n            return\n        profile = self.profile_data.get(profile_key)\n        if not profile:\n            return\n        fuel_rate = profile.get("fuel_rate")\n        if isinstance(fuel_rate, (float, int)) and fuel_rate > 0:\n            self.fuel_rate_var.set(f"{float(fuel_rate):.3f}")\n            self._fuel_rate_autofilled = True\n        base_loss = profile.get("base_loss")\n        if isinstance(base_loss, (float, int)) and base_loss >= 0:\n            self.base_loss_var.set(f"{float(base_loss):.2f}")\n        tire_loss = profile.get("tire_loss")\n        if isinstance(tire_loss, (float, int)) and tire_loss >= 0:\n            self.tire_loss_var.set(f"{float(tire_loss):.2f}")\n        custom_max = profile.get("custom_fuel_max")\n        if isinstance(custom_max, (float, int)) and custom_max > 0:\n            self.custom_fuel_max_var.set(f"{float(custom_max):.2f}")\n            self.use_custom_fuel_max_var.set(True)\n        else:\n            self.custom_fuel_max_var.set("")\n            self.use_custom_fuel_max_var.set(False)\n\n    def _persist_profile_inputs(self) -> None:\n        profile_key = self._profile_key(self.active_car_id, self.active_track_id)\n        if not profile_key:\n            return\n        profile = self.profile_data.setdefault(profile_key, {})\n        profile["base_loss"] = self._safe_float(self.base_loss_var.get(), default=20.0)\n        profile["tire_loss"] = self._safe_float(self.tire_loss_var.get(), default=0.0)\n\n        if self.use_custom_fuel_max_var.get():\n            custom_max = self._safe_float(self.custom_fuel_max_var.get(), default=0.0)\n            if custom_max > 0:\n                profile["custom_fuel_max"] = custom_max\n            else:\n                profile.pop("custom_fuel_max", None)\n        else:\n            profile.pop("custom_fuel_max", None)\n\n        self._save_profiles()\n\n    def _apply_lock_state(self) -> None:\n        state = "readonly" if self.lock_inputs_var.get() else "normal"\n        for entry in self._editable_entries:\n            entry.configure(state=state)\n\n    def _learn_fuel_rate(self) -> None:\n        now_s = self._read_telemetry("SessionTime")\n        fuel_now = self._read_telemetry("FuelLevel")\n        on_pit_road = bool(self._read_telemetry("OnPitRoad", 0))\n\n        if not isinstance(now_s, (float, int)) or not isinstance(fuel_now, (float, int)):\n            return\n\n        now_s = float(now_s)\n        fuel_now = float(fuel_now)\n\n        if self._last_tick_s is None or self._last_fuel_level is None:\n            self._last_tick_s = now_s\n            self._last_fuel_level = fuel_now\n            return\n\n        dt = now_s - self._last_tick_s\n        dfuel = fuel_now - self._last_fuel_level\n        self._last_tick_s = now_s\n        self._last_fuel_level = fuel_now\n\n        if dt <= 0:\n            return\n\n        if on_pit_road and dfuel > 0.01:\n            instant_rate = dfuel / dt\n            if instant_rate > 0:\n                self._fueling_samples.append(instant_rate)\n            self._is_fueling = True\n            return\n\n        profile_key = self._profile_key(self.active_car_id, self.active_track_id)\n        if self._is_fueling and self._fueling_samples and profile_key:\n            learned_rate = sum(self._fueling_samples) / len(self._fueling_samples)\n            profile = self.profile_data.setdefault(profile_key, {})\n            profile["fuel_rate"] = learned_rate\n            self.fuel_rate_var.set(f"{learned_rate:.3f}")\n            self._fuel_rate_autofilled = True\n            self._save_profiles()\n\n        self._is_fueling = False\n        self._fueling_samples = []\n\n    def _collect_car_deltas(self, lap_time_s: float) -> List[float]:\n        player_idx = self._read_telemetry("PlayerCarIdx")\n        car_est = self._read_telemetry("CarIdxEstTime")\n        track_surface = self._read_telemetry("CarIdxTrackSurface")\n\n        if player_idx is None or car_est is None:\n            return []\n\n        try:\n            player_idx = int(player_idx)\n            player_est = float(car_est[player_idx])\n        except Exception:\n            return []\n\n        deltas: List[float] = []\n        half_lap = max(10.0, lap_time_s / 2.0)\n\n        for idx, other_est in enumerate(car_est):\n            if idx == player_idx:\n                continue\n\n            if track_surface is not None:\n                try:\n                    surf = int(track_surface[idx])\n                    if surf < 0:\n                        continue\n                except Exception:\n                    pass\n\n            try:\n                delta = float(other_est) - player_est\n            except Exception:\n                continue\n\n            while delta > half_lap:\n                delta -= lap_time_s\n            while delta < -half_lap:\n                delta += lap_time_s\n            deltas.append(delta)\n\n        return deltas\n\n    @staticmethod\n    def _status_from_gaps(front_gap: float, rear_gap: float) -> Tuple[str, str, float]:\n        min_gap = min(front_gap, rear_gap)\n        score = max(0.0, min(100.0, (min_gap / GREEN_GAP_S) * 100.0))\n\n        if min_gap >= GREEN_GAP_S:\n            return "GREEN", "#15803d", score\n        if min_gap >= YELLOW_GAP_S:\n            return "YELLOW", "#ca8a04", score\n        return "RED", "#b91c1c", score\n\n    def _update(self) -> None:\n        connected = self.ir.startup() if not getattr(self.ir, "is_initialized", False) else True\n        if not connected:\n            self.connection_var.set("Not connected to iRacing. Open sim + click Drive.")\n            self.car_var.set("Car: --")\n            self.window_var.set("Awaiting telemetry")\n            self.status_var.set("Status: Waiting for telemetry...")\n            self.score_label.config(bg="#4b5563")\n            self.root.after(150, self._update)\n            return\n\n        self.connection_var.set(f"Connected. Updating every {UPDATE_MS} ms.")\n\n        car_id, car_name = self._driver_identity()\n        track_id, track_name = self._track_identity()\n        if car_id != self.active_car_id or track_id != self.active_track_id:\n            self.active_car_id = car_id\n            self.active_car_name = car_name\n            self.active_track_id = track_id\n            self.active_track_name = track_name\n            self._fuel_rate_autofilled = False\n            self._apply_profile_if_known(car_id, track_id)\n            self._is_fueling = False\n            self._fueling_samples = []\n        if car_name:\n            track_label = track_name or "Unknown track"\n            self.car_var.set(f"Car: {car_name}  |  Track: {track_label}")\n        else:\n            self.car_var.set("Car: Unknown")\n\n        self._learn_fuel_rate()\n        self._persist_profile_inputs()\n\n        base_loss = self._safe_float(self.base_loss_var.get(), default=20.0)\n        tire_loss = self._safe_float(self.tire_loss_var.get(), default=0.0)\n        fuel_rate = self._safe_float(self.fuel_rate_var.get(), default=2.2, minimum=0.001)\n\n        fuel_now = self._read_telemetry("FuelLevel", 0.0)\n        fuel_max = self._driver_fuel_max_liters()\n        if fuel_max is None:\n            fuel_max = self._read_telemetry("FuelLevel", 0.0)\n\n        if self.use_custom_fuel_max_var.get():\n            custom_max = self._safe_float(self.custom_fuel_max_var.get(), default=0.0)\n            if custom_max > 0:\n                fuel_max = custom_max\n\n        fuel_now = float(fuel_now or 0.0)\n        fuel_max = float(fuel_max or 0.0)\n        fuel_to_add = max(0.0, fuel_max - fuel_now)\n        fuel_time = fuel_to_add / fuel_rate if fuel_rate > 0 else 0.0\n\n        total_loss = base_loss + tire_loss + fuel_time\n\n        self.fuel_state_var.set(f"Fuel: {fuel_now:.2f} / {fuel_max:.2f} L (add {fuel_to_add:.2f} L)")\n        self.fuel_time_var.set(f"Fuel time: {fuel_time:.2f} s")\n        self.total_time_var.set(f"Total pit time loss: {total_loss:.2f} s")\n\n        lap_time_s = self._read_telemetry("DriverCarEstLapTime", DEFAULT_LAP_TIME_S)\n        if not isinstance(lap_time_s, (float, int)) or lap_time_s <= 1.0:\n            lap_time_s = self._read_telemetry("LapBestLapTime", DEFAULT_LAP_TIME_S)\n        if not isinstance(lap_time_s, (float, int)) or lap_time_s <= 1.0:\n            lap_time_s = DEFAULT_LAP_TIME_S\n        lap_time_s = float(lap_time_s)\n\n        deltas = self._collect_car_deltas(lap_time_s)\n        projected = [d + total_loss for d in deltas]\n\n        front_candidates = [d for d in projected if d >= 0]\n        rear_candidates = [d for d in projected if d < 0]\n\n        front_gap = min(front_candidates) if front_candidates else 99.0\n        rear_gap = abs(max(rear_candidates)) if rear_candidates else 99.0\n\n        status, color, score = self._status_from_gaps(front_gap, rear_gap)\n        self.score_label.config(bg=color)\n        self.window_var.set(f"{score:.0f}%   {status}")\n        self.status_var.set(\n            f"Projected rejoin gaps -> front: {front_gap:.2f} s, rear: {rear_gap:.2f} s\\n"\n            f"(using total pit time loss {total_loss:.2f} s)."\n        )\n\n        self.root.after(UPDATE_MS, self._update)\n\n    def run(self) -> None:\n        self._update()\n        self.root.mainloop()\n\n\ndef main() -> int:\n    app = PitStopOverlay()\n    app.run()\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n',
    'tirewear': '#!/usr/bin/env python3\n"""\niRacing Tire Wear Learning Overlay\n\nSingle-file application that:\n- Reads live telemetry from iRacing (irsdk) at 60 Hz\n- Detects stints and learns tire wear behavior over time\n- Uses driving load (|LatAccel| * Speed) and temperature modeling\n- Saves learned data by track+config+car into %APPDATA%/NishizumiTools (or ~/.config/NishizumiTools)\n- Shows a transparent overlay HUD and a settings/info menu (PyQt5)\n\nInstall:\n    pip install irsdk numpy pyqt5\nRun:\n    python Nishizumi_TireWear.py\n"""\nfrom __future__ import annotations\nimport json\nimport os\nimport queue\nimport re\nimport signal\nimport threading\nimport time\nfrom dataclasses import dataclass\nfrom pathlib import Path\nfrom typing import Dict, List, Optional, Tuple\n\nimport numpy as np\nfrom PyQt5 import QtCore, QtGui, QtWidgets\nimport irsdk\n\n\n\ndef _get_appdata_dir() -> Path:\n    root = Path(os.getenv("APPDATA") or Path.home() / ".config")\n    path = root / "NishizumiTools"\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\nAPPDATA_DIR = _get_appdata_dir()\nMODEL_PATH = str(APPDATA_DIR / "nishizumi_tirewear_model.json")\nSETTINGS_PATH = str(APPDATA_DIR / "nishizumi_tirewear_settings.json")\nTIRE_KEYS = ("lf", "rf", "lr", "rr")\nWEAR_FIELDS = {\n    "lf": ("LFwearL", "LFwearM", "LFwearR"),\n    "rf": ("RFwearL", "RFwearM", "RFwearR"),\n    "lr": ("LRwearL", "LRwearM", "LRwearR"),\n    "rr": ("RRwearL", "RRwearM", "RRwearR"),\n}\n# Inner shoulder for each tire (carcass side). For left tires it\'s "R", for right tires it\'s "L".\nINNER_WEAR_INDEX = {\n    "lf": 2,\n    "rf": 0,\n    "lr": 2,\n    "rr": 0,\n}\nPIT_TIRE_CHANGE_FLAGS = {\n    "lf": 0x0001,\n    "rf": 0x0002,\n    "lr": 0x0004,\n    "rr": 0x0008,\n}\n\n\n@dataclass\nclass TelemetrySnapshot:\n    """Immutable snapshot of telemetry values consumed by the model worker."""\n\n    session_time: float\n    lap: int\n    lap_dist_pct: float\n    on_pit_road: bool\n    speed_mps: float\n    lat_accel: float\n    long_accel: float\n    steering: float\n    track_temp: float\n    air_temp: float\n    humidity: float\n    pit_sv_flags: int\n    wear: Dict[str, float]\n    track_name: str\n    track_config: str\n    car_path: str\n\n\nclass DataStorage:\n    """Thread-safe JSON persistence for learned tire model samples."""\n\n    def __init__(self, path: str = MODEL_PATH):\n        self.path = path\n        self.lock = threading.Lock()\n        self.data = self._load()\n        self._ensure_model_file_exists()\n\n    def _ensure_model_file_exists(self):\n        """Create an empty model file so persistence is visible before first sample."""\n        if os.path.exists(self.path):\n            return\n        try:\n            with open(self.path, "w", encoding="utf-8") as f:\n                json.dump(self.data, f, indent=2)\n        except Exception:\n            # Non-fatal: learning can still proceed and save later.\n            pass\n\n    def _load(self) -> Dict[str, dict]:\n        if not os.path.exists(self.path):\n            return {}\n        try:\n            with open(self.path, "r", encoding="utf-8") as f:\n                raw = json.load(f)\n            return raw if isinstance(raw, dict) else {}\n        except Exception:\n            return {}\n\n    def save(self):\n        with self.lock:\n            tmp = self.path + ".tmp"\n            with open(tmp, "w", encoding="utf-8") as f:\n                json.dump(self.data, f, indent=2)\n            os.replace(tmp, self.path)\n\n    def get_samples(self, key: str) -> List[dict]:\n        with self.lock:\n            return list(self.data.get(key, {}).get("samples", []))\n\n    def add_sample(self, key: str, sample: dict):\n        with self.lock:\n            if key not in self.data:\n                self.data[key] = {"samples": []}\n            self.data[key]["samples"].append(sample)\n\n\n_PHI_DIM = 7\n\n\ndef _phi(track_temp: float, air_temp: float, humidity: float, energy_per_lap: float) -> np.ndarray:\n    t_track = float(track_temp)\n    e_lap = float(energy_per_lap)\n    return np.array(\n        [\n            1.0,\n            t_track,\n            t_track * t_track,\n            float(air_temp),\n            float(humidity),\n            e_lap,\n            t_track * e_lap,\n        ],\n        dtype=float,\n    )\n\n\nclass RLSEstimator:\n    """Single-target recursive least squares estimator."""\n\n    def __init__(self, lam: float = 0.98, sigma0: float = 1e4):\n        self.lam = float(lam)\n        self.theta = np.zeros(_PHI_DIM, dtype=float)\n        self.P = float(sigma0) * np.eye(_PHI_DIM, dtype=float)\n        self.n_updates = 0\n        self.mad_error = 1e-4\n\n    def update(self, x: np.ndarray, y: float) -> float:\n        px = self.P @ x\n        gain = px / (self.lam + float(x @ px))\n        error = float(y) - float(x @ self.theta)\n        self.theta += gain * error\n        self.P = (self.P - np.outer(gain, px)) / self.lam\n        self.n_updates += 1\n        self.mad_error = 0.95 * self.mad_error + 0.05 * abs(error)\n        return error\n\n    def predict(self, x: np.ndarray) -> float:\n        return max(0.0, float(x @ self.theta))\n\n    @property\n    def confidence(self) -> float:\n        return float(np.tanh(self.n_updates / 13.0))\n\n    @property\n    def uncertainty_trace(self) -> float:\n        return float(np.trace(self.P))\n\n    def to_dict(self) -> dict:\n        return {\n            "theta": self.theta.tolist(),\n            "P": [r.tolist() for r in self.P],\n            "n_updates": int(self.n_updates),\n            "lam": float(self.lam),\n            "mad_error": float(self.mad_error),\n        }\n\n    @classmethod\n    def from_dict(cls, data: dict) -> "RLSEstimator":\n        obj = cls(lam=float(data.get("lam", 0.98)))\n        obj.theta = np.array(data.get("theta", np.zeros(_PHI_DIM)), dtype=float)\n        obj.P = np.array(data.get("P", np.eye(_PHI_DIM) * 1e4), dtype=float)\n        obj.n_updates = int(data.get("n_updates", 0))\n        obj.mad_error = max(1e-6, float(data.get("mad_error", 1e-4)))\n        return obj\n\n\nclass TireMLModel:\n    """Persistent online tire wear model powered by RLS per tire."""\n\n    def __init__(self, storage: DataStorage):\n        self.storage = storage\n        self._rls: Dict[str, RLSEstimator] = {t: RLSEstimator() for t in TIRE_KEYS}\n\n    @staticmethod\n    def _rls_key(dataset_key: str) -> str:\n        return f"{dataset_key}::rls"\n\n    def load_rls(self, dataset_key: str):\n        with self.storage.lock:\n            raw = self.storage.data.get(self._rls_key(dataset_key), {})\n        for tire in TIRE_KEYS:\n            self._rls[tire] = RLSEstimator.from_dict(raw[tire]) if tire in raw else RLSEstimator()\n\n    def save_rls(self, dataset_key: str):\n        with self.storage.lock:\n            self.storage.data[self._rls_key(dataset_key)] = {t: self._rls[t].to_dict() for t in TIRE_KEYS}\n        self.storage.save()\n\n    def add_stint_sample(self, dataset_key: str, sample: dict):\n        self.storage.add_sample(dataset_key, sample)\n        x = _phi(\n            float(sample["track_temp"]),\n            float(sample["air_temp"]),\n            float(sample.get("humidity", 50.0)),\n            float(sample.get("energy_per_lap", 0.0)),\n        )\n        for tire in TIRE_KEYS:\n            self._rls[tire].update(x, float(sample[tire]))\n        self.save_rls(dataset_key)\n\n    def is_outlier(self, dataset_key: str, candidate: dict) -> bool:\n        x = _phi(\n            float(candidate["track_temp"]),\n            float(candidate["air_temp"]),\n            float(candidate.get("humidity", 50.0)),\n            float(candidate.get("energy_per_lap", 0.0)),\n        )\n        for tire in TIRE_KEYS:\n            rls = self._rls[tire]\n            if rls.n_updates < 4:\n                continue\n            pred = rls.predict(x)\n            pred_var = max(1e-10, float(x @ rls.P @ x) + rls.mad_error * rls.mad_error)\n            z = abs(float(candidate[tire]) - pred) / pred_var**0.5\n            if z > 3.5:\n                return True\n        return False\n\n    def get_rates(\n        self,\n        dataset_key: str,\n        track_temp: float,\n        air_temp: float = 25.0,\n        humidity: float = 50.0,\n        energy_per_lap: float = 0.0,\n    ) -> Tuple[Dict[str, float], float, int]:\n        sample_count = self.sample_count(dataset_key)\n        if self._rls["lf"].n_updates == 0:\n            return {t: 0.0 for t in TIRE_KEYS}, 0.0, sample_count\n\n        x = _phi(track_temp, air_temp, humidity, energy_per_lap)\n        samples = self.storage.get_samples(dataset_key)\n        rates = {}\n        for tire in TIRE_KEYS:\n            rls = self._rls[tire]\n            conf = rls.confidence\n            prior = float(np.median([float(s[tire]) for s in samples if tire in s])) if samples else 0.0\n            rates[tire] = max(0.0, conf * rls.predict(x) + (1.0 - conf) * prior)\n        return rates, self._rls["lf"].confidence, sample_count\n\n    def sample_count(self, key: str) -> int:\n        return len(self.storage.get_samples(key))\n\n    def get_wear_per_lap_baseline(\n        self,\n        key: str,\n        track_temp: float,\n        air_temp: float = 25.0,\n        humidity: float = 50.0,\n    ) -> Dict[str, float]:\n        samples = self.storage.get_samples(key)\n        if not samples:\n            return {t: 0.0 for t in TIRE_KEYS}\n\n        med_epl = float(np.median([float(s.get("energy_per_lap", 0.0)) for s in samples]))\n        rates, _, _ = self.get_rates(key, track_temp, air_temp, humidity, med_epl)\n        return {t: rates[t] * med_epl for t in TIRE_KEYS}\n\n    def get_coefficients_report(self, dataset_key: str) -> str:\n        names = ["bias", "T_track", "T_track²", "T_air", "humidity", "E/lap", "T_track×E/lap"]\n        lines = [f"=== Coefficients: {dataset_key} ==="]\n        for tire in TIRE_KEYS:\n            rls = self._rls[tire]\n            lines.append(\n                f"\\n[{tire.upper()}] n={rls.n_updates}  conf={rls.confidence:.1%}  "\n                f"P_trace={rls.uncertainty_trace:.2e}"\n            )\n            for name, coef in zip(names, rls.theta):\n                lines.append(f"  {name:20s}: {coef:+.6e}")\n        return "\\n".join(lines)\n\n\nclass StintTracker:\n    """Detects stint boundaries and computes validated learning samples at pit-in."""\n\n    MIN_LAPS = 2\n    LAP_STD_THRESHOLD = 15.0\n    PIT_WEAR_RESET_THRESHOLD = 5.0\n\n    def __init__(self):\n        self.in_stint = False\n        self.prev_on_pit: Optional[bool] = None\n        self.start_data: Dict[str, object] = {}\n\n        self.current_energy = 0.0\n        self.last_snapshot: Optional[TelemetrySnapshot] = None\n\n        self.last_lap: Optional[int] = None\n        self.last_lap_cross_time: Optional[float] = None\n        self.lap_times: List[float] = []\n        self.min_speed_kmh = float("inf")\n        self.stopped_in_pit = False\n        self.pit_tire_change_request = {t: False for t in TIRE_KEYS}\n        self.pit_entry_wear: Optional[Dict[str, float]] = None\n\n    @staticmethod\n    def make_dataset_key(s: TelemetrySnapshot) -> str:\n        def clean(text: str, fallback: str) -> str:\n            return (text or fallback).strip().lower().replace(" ", "_")\n\n        track = clean(s.track_name, "unknown_track")\n        config = clean(s.track_config, "default")\n        car = clean(s.car_path, "unknown_car")\n        return f"{track}+{config}+{car}"\n\n    @staticmethod\n    def laps_in_stint(current: TelemetrySnapshot, previous: TelemetrySnapshot) -> float:\n        """Return lap progress completed between two snapshots.\n\n        Uses lap + lap distance percent so partial laps are accounted for while\n        avoiding negative jumps across session resets/rewinds.\n        """\n\n        prev_progress = float(previous.lap) + float(previous.lap_dist_pct)\n        curr_progress = float(current.lap) + float(current.lap_dist_pct)\n        return max(0.0, curr_progress - prev_progress)\n\n    def _start_stint(self, snapshot: TelemetrySnapshot, speed_kmh: float):\n        """Initialize a new stint from the current telemetry snapshot."""\n\n        start_wear = dict(snapshot.wear)\n        if self.stopped_in_pit:\n            for tire in TIRE_KEYS:\n                if self.pit_tire_change_request.get(tire, False):\n                    start_wear[tire] = 100.0\n        self.in_stint = True\n        self.start_data = {\n            "wear": start_wear,\n            "session_time": snapshot.session_time,\n            "lap": snapshot.lap,\n            "lap_progress": float(snapshot.lap) + float(snapshot.lap_dist_pct),\n            "energy": self.current_energy,\n            "track_temp": snapshot.track_temp,\n            "air_temp": snapshot.air_temp,\n            "key": self.make_dataset_key(snapshot),\n        }\n        self.lap_times = []\n        self.min_speed_kmh = speed_kmh\n        self.stopped_in_pit = False\n        self.pit_tire_change_request = {t: False for t in TIRE_KEYS}\n        self.pit_entry_wear = None\n\n    def _infer_pit_tire_changes_from_wear(self, current_wear: Dict[str, float]):\n        """Infer tire swaps by comparing pit entry wear versus current wear.\n\n        iRacing pit service checkboxes can briefly flip while service is applied,\n        so we also detect a tire change when tread unexpectedly increases while\n        on pit road (fresh tire reset behavior).\n        """\n\n        if not self.pit_entry_wear:\n            return\n\n        for tire in TIRE_KEYS:\n            before = float(self.pit_entry_wear.get(tire, 0.0))\n            now = float(current_wear.get(tire, before))\n            wear_gain = now - before\n            if wear_gain >= self.PIT_WEAR_RESET_THRESHOLD:\n                self.pit_tire_change_request[tire] = True\n\n    def update(self, snapshot: TelemetrySnapshot) -> Optional[dict]:\n        speed_kmh = snapshot.speed_mps * 3.6\n        self.min_speed_kmh = min(self.min_speed_kmh, speed_kmh)\n\n        if snapshot.on_pit_road and speed_kmh < 1.0:\n            self.stopped_in_pit = True\n\n        if snapshot.on_pit_road:\n            if self.pit_entry_wear is None:\n                self.pit_entry_wear = dict(snapshot.wear)\n            flags = int(snapshot.pit_sv_flags)\n            for tire, bit in PIT_TIRE_CHANGE_FLAGS.items():\n                # Mirror the live pit checkbox state while stopped in pit.\n                # This allows last-second unchecks to cancel planned changes.\n                self.pit_tire_change_request[tire] = bool(flags & bit)\n            self._infer_pit_tire_changes_from_wear(snapshot.wear)\n\n        # Driving load energy integration.\n        if self.last_snapshot is not None:\n            dt = max(0.0, snapshot.session_time - self.last_snapshot.session_time)\n            self.current_energy += abs(snapshot.lat_accel) * snapshot.speed_mps * dt\n\n        # Capture lap times for outlier rejection.\n        if self.last_lap is None:\n            self.last_lap = snapshot.lap\n            self.last_lap_cross_time = snapshot.session_time\n        elif snapshot.lap > self.last_lap:\n            if self.last_lap_cross_time is not None:\n                lap_time = snapshot.session_time - self.last_lap_cross_time\n                if 20.0 <= lap_time <= 500.0:\n                    self.lap_times.append(lap_time)\n            self.last_lap_cross_time = snapshot.session_time\n            self.last_lap = snapshot.lap\n\n        result = None\n        if self.prev_on_pit is None:\n            self.prev_on_pit = snapshot.on_pit_road\n\n            # App can start while already on-track. Bootstrap a stint so live wear\n            # and first learning sample work without requiring a full pit cycle first.\n            if not snapshot.on_pit_road:\n                self._start_stint(snapshot, speed_kmh)\n\n        # Stint start: in pit before, now not in pit.\n        if (not snapshot.on_pit_road) and bool(self.prev_on_pit):\n            self._start_stint(snapshot, speed_kmh)\n\n        # Stint end: was out of pit, now entered pit.\n        if snapshot.on_pit_road and (not bool(self.prev_on_pit)) and self.in_stint:\n            self.in_stint = False\n\n            laps = max(0, snapshot.lap - int(self.start_data.get("lap", snapshot.lap)))\n            start_energy = float(self.start_data.get("energy", self.current_energy))\n            energy_used = max(1e-9, self.current_energy - start_energy)\n\n            wear_start = self.start_data.get("wear", snapshot.wear)\n            wear_end = snapshot.wear\n            wear_delta = {t: max(0.0, float(wear_start[t]) - float(wear_end[t])) for t in TIRE_KEYS}\n            wear_per_lap = {t: wear_delta[t] / laps if laps > 0 else 0.0 for t in TIRE_KEYS}\n            wear_per_energy = {t: wear_delta[t] / energy_used for t in TIRE_KEYS}\n            energy_per_lap = energy_used / laps if laps > 0 else 0.0\n\n            lap_std = float(np.std(self.lap_times)) if len(self.lap_times) >= 2 else 0.0\n\n            result = {\n                "key": self.start_data.get("key"),\n                "laps": laps,\n                "lap_std": lap_std,\n                "lap_times": list(self.lap_times),\n                "min_speed_kmh": self.min_speed_kmh,\n                "track_temp": float(snapshot.track_temp),\n                "air_temp": float(snapshot.air_temp),\n                "humidity": float(snapshot.humidity),\n                "energy_per_lap": float(energy_per_lap),\n                "wear_per_lap": wear_per_lap,\n                "wear_per_energy": wear_per_energy,\n            }\n\n        self.prev_on_pit = snapshot.on_pit_road\n        self.last_snapshot = snapshot\n        return result\n\n    def stint_is_valid(self, stint: dict) -> bool:\n        if stint["laps"] < self.MIN_LAPS:\n            return False\n\n        # Out-lap and in-lap tend to be much slower and can cause false rejects.\n        lap_times = list(stint.get("lap_times", []))\n        if len(lap_times) > 2:\n            lap_times = lap_times[1:-1]\n\n        if len(lap_times) >= 2 and float(np.std(lap_times)) > self.LAP_STD_THRESHOLD:\n            return False\n        if stint["min_speed_kmh"] < 20.0:\n            return False\n        return True\n\n    def build_live_estimate(\n        self,\n        snapshot: TelemetrySnapshot,\n        rates_per_energy: Dict[str, float],\n        baseline_wear_per_lap: Dict[str, float],\n    ) -> Optional[dict]:\n        if not self.in_stint or not self.start_data:\n            return None\n\n        start_energy = float(self.start_data.get("energy", self.current_energy))\n        energy_used = max(0.0, self.current_energy - start_energy)\n        initial_wear = self.start_data.get("wear", snapshot.wear)\n        start_lap_progress = float(self.start_data.get("lap_progress", float(snapshot.lap) + float(snapshot.lap_dist_pct)))\n        current_lap_progress = float(snapshot.lap) + float(snapshot.lap_dist_pct)\n        laps_progress = max(0.0, current_lap_progress - start_lap_progress)\n\n        estimated_tread = {}\n        for tire in TIRE_KEYS:\n            predicted_wear_energy = energy_used * float(rates_per_energy.get(tire, 0.0))\n            predicted_wear_laps = laps_progress * float(baseline_wear_per_lap.get(tire, 0.0))\n            predicted_wear = max(predicted_wear_energy, predicted_wear_laps)\n            estimated_tread[tire] = float(np.clip(float(initial_wear[tire]) - predicted_wear, 0.0, 100.0))\n\n        laps_done = max(0, snapshot.lap - int(self.start_data.get("lap", snapshot.lap)))\n        return {\n            "estimated_tread": estimated_tread,\n            "energy_used": energy_used,\n            "laps_done": laps_done,\n            "laps_progress": laps_progress,\n        }\n\n\nclass TelemetryReader(threading.Thread):\n    """60 Hz telemetry reader; reconnects automatically if sim/session restarts."""\n\n    def __init__(self, out_queue: queue.Queue, stop_event: threading.Event):\n        super().__init__(daemon=True)\n        self.out_queue = out_queue\n        self.stop_event = stop_event\n        self.ir = irsdk.IRSDK()\n        self.last_meta = {"TrackName": "", "TrackConfigName": "", "CarPath": ""}\n\n    @staticmethod\n    def _safe_float(v, default=0.0) -> float:\n        try:\n            return float(v) if v is not None else float(default)\n        except Exception:\n            return float(default)\n\n    @staticmethod\n    def _safe_int(v, default=0) -> int:\n        try:\n            return int(v) if v is not None else int(default)\n        except Exception:\n            return int(default)\n\n    def _connected(self) -> bool:\n        try:\n            if not getattr(self.ir, "is_initialized", False):\n                self.ir.startup()\n            return bool(getattr(self.ir, "is_connected", False))\n        except Exception:\n            return False\n\n    def _parse_metadata(self) -> Dict[str, str]:\n        def prettify(text: str) -> str:\n            cleaned = re.sub(r"[_\\-]+", " ", str(text or "")).strip()\n            return cleaned.title()\n\n        # Primary source (same approach used in the main app): direct iRacing blocks.\n        try:\n            weekend = self.ir["WeekendInfo"]\n            if isinstance(weekend, dict):\n                track_name = str(weekend.get("TrackDisplayName") or weekend.get("TrackName") or "").strip()\n                track_config = str(weekend.get("TrackConfigName") or "").strip()\n                if track_name:\n                    self.last_meta["TrackName"] = prettify(track_name)\n                if track_config:\n                    self.last_meta["TrackConfigName"] = prettify(track_config)\n        except Exception:\n            pass\n\n        try:\n            driver_info = self.ir["DriverInfo"]\n            if isinstance(driver_info, dict):\n                drivers = driver_info.get("Drivers") or []\n                idx = driver_info.get("DriverCarIdx")\n                try:\n                    idx = int(idx) if idx is not None else None\n                except (TypeError, ValueError):\n                    idx = None\n                if idx is not None and 0 <= idx < len(drivers) and isinstance(drivers[idx], dict):\n                    entry = drivers[idx]\n                    car_path = str(\n                        entry.get("CarScreenName")\n                        or entry.get("CarScreenNameShort")\n                        or entry.get("CarPath")\n                        or ""\n                    ).strip()\n                    if car_path:\n                        self.last_meta["CarPath"] = prettify(car_path)\n        except Exception:\n            pass\n\n        if any(self.last_meta.values()):\n            return self.last_meta\n\n        # Prefer parsed SessionInfo dict and fallback to session YAML string.\n        try:\n            session_info = self.ir["SessionInfo"]\n            if isinstance(session_info, dict):\n                weekend = session_info.get("WeekendInfo") or {}\n                driver_info = session_info.get("DriverInfo") or {}\n                drivers = driver_info.get("Drivers") or []\n                # PlayerCarIdx is the stable identifier for the local car.\n                player_car_idx = self._safe_int(self.ir["PlayerCarIdx"], -1)\n\n                track_name = str(weekend.get("TrackDisplayName") or weekend.get("TrackName") or "").strip()\n                track_config = str(weekend.get("TrackConfigName") or "").strip()\n                car_path = ""\n                player_car = None\n                for entry in drivers:\n                    if not isinstance(entry, dict):\n                        continue\n                    if self._safe_int(entry.get("CarIdx"), -1) == player_car_idx:\n                        player_car = entry\n                        break\n\n                # Fallback for older/odd payloads where list index may match the car idx.\n                if player_car is None and 0 <= player_car_idx < len(drivers):\n                    candidate = drivers[player_car_idx]\n                    if isinstance(candidate, dict):\n                        player_car = candidate\n\n                if isinstance(player_car, dict):\n                    car_path = str(\n                        player_car.get("CarScreenName")\n                        or player_car.get("CarScreenNameShort")\n                        or player_car.get("CarPath")\n                        or ""\n                    ).strip()\n\n                track_name = prettify(track_name)\n                track_config = prettify(track_config)\n                car_path = prettify(car_path)\n\n                if track_name:\n                    self.last_meta["TrackName"] = track_name\n                if track_config:\n                    self.last_meta["TrackConfigName"] = track_config\n                if car_path:\n                    self.last_meta["CarPath"] = car_path\n\n                if track_name or track_config or car_path:\n                    return self.last_meta\n        except Exception:\n            pass\n\n        text = ""\n        try:\n            text = self.ir.session_info\n        except Exception:\n            pass\n\n        if not text:\n            return self.last_meta\n\n        # YAML fallback parsing.\n        m_track = re.search(r"^\\s*TrackDisplayName:\\s*(.+?)\\s*$", text, flags=re.MULTILINE)\n        if m_track:\n            self.last_meta["TrackName"] = m_track.group(1).strip().strip(\'"\')\n        else:\n            m_track_name = re.search(r"^\\s*TrackName:\\s*(.+?)\\s*$", text, flags=re.MULTILINE)\n            if m_track_name:\n                self.last_meta["TrackName"] = m_track_name.group(1).strip().strip(\'"\')\n\n        m_cfg = re.search(r"^\\s*TrackConfigName:\\s*(.+?)\\s*$", text, flags=re.MULTILINE)\n        if m_cfg:\n            self.last_meta["TrackConfigName"] = m_cfg.group(1).strip().strip(\'"\')\n\n        m_car = re.search(r"^\\s*CarScreenName:\\s*(.+?)\\s*$", text, flags=re.MULTILINE)\n        if m_car:\n            self.last_meta["CarPath"] = m_car.group(1).strip().strip(\'"\')\n        else:\n            m_car_path = re.search(r"^\\s*CarPath:\\s*(.+?)\\s*$", text, flags=re.MULTILINE)\n            if m_car_path:\n                self.last_meta["CarPath"] = m_car_path.group(1).strip().strip(\'"\')\n\n        self.last_meta["TrackName"] = prettify(self.last_meta.get("TrackName", ""))\n        self.last_meta["TrackConfigName"] = prettify(self.last_meta.get("TrackConfigName", ""))\n        self.last_meta["CarPath"] = prettify(self.last_meta.get("CarPath", ""))\n        return self.last_meta\n\n    @staticmethod\n    def _normalize_wear_value(value: float) -> float:\n        # Depending on sdk/version tire wear can be [0..1] fraction or [0..100] percent.\n        v = max(0.0, float(value))\n        return v * 100.0 if v <= 1.5 else v\n\n    def run(self):\n        tick_s = 1.0 / 60.0\n        while not self.stop_event.is_set():\n            try:\n                if not self._connected():\n                    # Push disconnected marker snapshot-less event through queue state.\n                    self.out_queue.put_nowait((None, False))\n                    time.sleep(1.0)\n                    continue\n\n                meta = self._parse_metadata()\n                wear = {}\n                for tire, fields in WEAR_FIELDS.items():\n                    inner_index = INNER_WEAR_INDEX[tire]\n                    inner_field = fields[inner_index]\n                    wear[tire] = self._normalize_wear_value(self._safe_float(self.ir[inner_field], 100.0))\n\n                snap = TelemetrySnapshot(\n                    session_time=self._safe_float(self.ir["SessionTime"], 0.0),\n                    lap=self._safe_int(self.ir["Lap"], 0),\n                    lap_dist_pct=self._safe_float(self.ir["LapDistPct"], 0.0),\n                    on_pit_road=bool(self.ir["OnPitRoad"]),\n                    speed_mps=self._safe_float(self.ir["Speed"], 0.0),\n                    lat_accel=self._safe_float(self.ir["LatAccel"], 0.0),\n                    long_accel=self._safe_float(self.ir["LongAccel"], 0.0),\n                    steering=self._safe_float(self.ir["SteeringWheelAngle"], 0.0),\n                    track_temp=self._safe_float(self.ir["TrackTemp"], 0.0),\n                    air_temp=self._safe_float(self.ir["AirTemp"], 0.0),\n                    humidity=self._safe_float(self.ir["RelativeHumidity"], 0.0),\n                    pit_sv_flags=self._safe_int(self.ir["PitSvFlags"], 0),\n                    wear=wear,\n                    track_name=meta.get("TrackName", ""),\n                    track_config=meta.get("TrackConfigName", ""),\n                    car_path=meta.get("CarPath", ""),\n                )\n                self.out_queue.put_nowait((snap, True))\n                time.sleep(tick_s)\n            except queue.Full:\n                time.sleep(tick_s)\n            except Exception:\n                # Telemetry can disappear mid-session; keep looping.\n                time.sleep(0.2)\n\n\nclass ModelWorker(threading.Thread):\n    """Model thread that performs live estimation and incremental learning."""\n\n    def __init__(self, in_queue: queue.Queue, state: dict, state_lock: threading.Lock, stop_event: threading.Event):\n        super().__init__(daemon=True)\n        self.in_queue = in_queue\n        self.state = state\n        self.state_lock = state_lock\n        self.stop_event = stop_event\n        self.storage = DataStorage(MODEL_PATH)\n        self.model = TireMLModel(self.storage)\n        self._last_key = ""\n        self.stints = StintTracker()\n        self.smoothed_wear_per_lap = {t: 0.0 for t in TIRE_KEYS}\n\n    def _update_state(self, **kwargs):\n        with self.state_lock:\n            self.state.update(kwargs)\n            self.state["updated_at"] = time.time()\n\n    def _consume_reset_request(self) -> bool:\n        with self.state_lock:\n            if not self.state.get("reset_requested", False):\n                return False\n            self.state["reset_requested"] = False\n            return True\n\n    def _reset_runtime_memory(self):\n        self.storage.data = {}\n        self.storage.save()\n        self.stints = StintTracker()\n        self.smoothed_wear_per_lap = {t: 0.0 for t in TIRE_KEYS}\n        self._update_state(\n            tread={t: 100.0 for t in TIRE_KEYS},\n            wear_per_lap={t: 0.0 for t in TIRE_KEYS},\n            key="",\n            model_confidence=0.0,\n            sample_count=0,\n            estimate_ready=False,\n        )\n\n    def run(self):\n        while not self.stop_event.is_set():\n            try:\n                payload = self.in_queue.get(timeout=0.5)\n            except queue.Empty:\n                continue\n\n            snap, connected = payload\n            self._update_state(connected=bool(connected))\n            if self._consume_reset_request():\n                self._reset_runtime_memory()\n            if snap is None:\n                continue\n\n            key = StintTracker.make_dataset_key(snap)\n            if key != self._last_key:\n                self.model.load_rls(key)\n                self._last_key = key\n\n            live_laps_done = 0.0\n            if self.stints.last_snapshot is not None:\n                live_laps_done = self.stints.laps_in_stint(snap, self.stints.last_snapshot)\n            live_energy_per_lap = self.stints.current_energy / max(1.0, live_laps_done)\n\n            rates_energy, model_confidence, sample_count = self.model.get_rates(\n                key,\n                snap.track_temp,\n                snap.air_temp,\n                snap.humidity,\n                live_energy_per_lap,\n            )\n            baseline_wear_per_lap = self.model.get_wear_per_lap_baseline(\n                key,\n                snap.track_temp,\n                snap.air_temp,\n                snap.humidity,\n            )\n            self._update_state(\n                key=key,\n                track_temp=snap.track_temp,\n                air_temp=snap.air_temp,\n                humidity=snap.humidity,\n                model_confidence=model_confidence,\n                sample_count=sample_count,\n                track_name=snap.track_name,\n                track_config=snap.track_config,\n                car_path=snap.car_path,\n            )\n\n            has_base_samples = sample_count >= 1\n            self._update_state(estimate_ready=has_base_samples)\n\n            stint_end = self.stints.update(snap)\n            live = self.stints.build_live_estimate(snap, rates_energy, baseline_wear_per_lap) if has_base_samples else None\n            if live:\n                laps_done = max(1e-6, live.get("laps_progress", float(live["laps_done"])))\n                energy_per_lap_live = live["energy_used"] / laps_done\n                current_wpl = {t: rates_energy[t] * energy_per_lap_live for t in TIRE_KEYS}\n                for t in TIRE_KEYS:\n                    current_wpl[t] = max(current_wpl[t], baseline_wear_per_lap.get(t, 0.0))\n\n                # Exponential smoothing for stable wear rate estimate.\n                for t in TIRE_KEYS:\n                    self.smoothed_wear_per_lap[t] = 0.8 * self.smoothed_wear_per_lap[t] + 0.2 * current_wpl[t]\n\n                self._update_state(\n                    tread=dict(live["estimated_tread"]),\n                    wear_per_lap=dict(self.smoothed_wear_per_lap),\n                )\n            elif not has_base_samples:\n                self._update_state(wear_per_lap={t: 0.0 for t in TIRE_KEYS})\n\n            if not stint_end:\n                continue\n\n            if not self.stints.stint_is_valid(stint_end):\n                continue\n\n            sample = {\n                "track_temp": float(stint_end["track_temp"]),\n                "air_temp": float(stint_end["air_temp"]),\n                "laps": int(stint_end["laps"]),\n                "energy_per_lap": float(stint_end["energy_per_lap"]),\n                "lf": float(stint_end["wear_per_energy"]["lf"]),\n                "rf": float(stint_end["wear_per_energy"]["rf"]),\n                "lr": float(stint_end["wear_per_energy"]["lr"]),\n                "rr": float(stint_end["wear_per_energy"]["rr"]),\n            }\n\n            sample["humidity"] = float(stint_end.get("humidity", 50.0))\n\n            if self.model.is_outlier(str(stint_end["key"]), sample):\n                continue\n\n            self.model.add_stint_sample(str(stint_end["key"]), sample)\n            self._update_state(\n                sample_count=self.model.sample_count(key),\n                model_confidence=self.model._rls["lf"].confidence,\n            )\n\n\nclass InfoDialog(QtWidgets.QDialog):\n    """Information panel showing model/session status and learned data details."""\n\n    def __init__(self, parent: QtWidgets.QWidget):\n        super().__init__(parent)\n        self.setWindowTitle("Tire Overlay - Information")\n        self.resize(520, 300)\n\n        self.text = QtWidgets.QPlainTextEdit(self)\n        self.text.setReadOnly(True)\n        self.text.setStyleSheet(\n            """\n            QPlainTextEdit {\n                background-color: #1B1B1B;\n                color: #FFFFFF;\n                border: 1px solid #4A4A4A;\n                selection-background-color: #3E6EA8;\n                selection-color: #FFFFFF;\n            }\n            """\n        )\n\n        btn_close = QtWidgets.QPushButton("Close")\n        btn_close.clicked.connect(self.close)\n\n        lay = QtWidgets.QVBoxLayout(self)\n        lay.addWidget(self.text)\n        lay.addWidget(btn_close, alignment=QtCore.Qt.AlignRight)\n        self.setStyleSheet(\n            """\n            QDialog {\n                background-color: #202020;\n                color: #FFFFFF;\n            }\n            QPushButton {\n                background-color: #2A2A2A;\n                color: #FFFFFF;\n                border: 1px solid #5A5A5A;\n                padding: 4px 10px;\n                min-width: 72px;\n            }\n            QPushButton:hover {\n                background-color: #3A3A3A;\n            }\n            """\n        )\n\n    def set_info(self, message: str):\n        self.text.setPlainText(message)\n\n\nclass QuickStartDialog(QtWidgets.QDialog):\n    """Short usage guide accessible from settings."""\n\n    GUIDE_TEXT = (\n        "Quick Start Guide\\n"\n        "=================\\n\\n"\n        "1. Launch iRacing and join a session.\\n"\n        "2. Start this app to show the tire wear overlay.\\n"\n        "3. Drag the overlay to the position you want on screen.\\n"\n        "4. Open Settings (⚙) to change size, font, opacity, or keep it always on top.\\n"\n        "5. Drive clean laps and complete stints so the model can learn your tire wear.\\n"\n        "6. Click the Information button (ℹ) to review connection status, temperatures, sample count, and model confidence.\\n"\n        "7. Use Reset data only if you want to erase the learned tire wear history and start over.\\n\\n"\n        "Tips\\n"\n        "----\\n"\n        "- Green tires are healthy, yellow means moderate wear, and red means heavy wear.\\n"\n        "- Model confidence improves after the app records more completed stints for the same car and track.\\n"\n        "- If the SDK shows OFFLINE, make sure iRacing is running and telemetry is available."\n    )\n\n    def __init__(self, parent: QtWidgets.QWidget):\n        super().__init__(parent)\n        self.setWindowTitle("Tire Overlay - Quick Start")\n        self.resize(560, 360)\n\n        self.text = QtWidgets.QPlainTextEdit(self)\n        self.text.setReadOnly(True)\n        self.text.setPlainText(self.GUIDE_TEXT)\n        self.text.setStyleSheet(\n            """\n            QPlainTextEdit {\n                background-color: #1B1B1B;\n                color: #FFFFFF;\n                border: 1px solid #4A4A4A;\n                selection-background-color: #3E6EA8;\n                selection-color: #FFFFFF;\n            }\n            """\n        )\n\n        btn_close = QtWidgets.QPushButton("Close")\n        btn_close.clicked.connect(self.close)\n\n        lay = QtWidgets.QVBoxLayout(self)\n        lay.addWidget(self.text)\n        lay.addWidget(btn_close, alignment=QtCore.Qt.AlignRight)\n        self.setStyleSheet(\n            """\n            QDialog {\n                background-color: #202020;\n                color: #FFFFFF;\n            }\n            QPushButton {\n                background-color: #2A2A2A;\n                color: #FFFFFF;\n                border: 1px solid #5A5A5A;\n                padding: 4px 10px;\n                min-width: 72px;\n            }\n            QPushButton:hover {\n                background-color: #3A3A3A;\n            }\n            """\n        )\n\n\nclass SettingsDialog(QtWidgets.QDialog):\n    """Simple settings menu for overlay behavior and appearance."""\n\n    def __init__(self, parent: "OverlayUI"):\n        super().__init__(parent)\n        self.parent_overlay = parent\n        self.setWindowTitle("Tire Overlay - Settings")\n        self.setWindowFlag(QtCore.Qt.WindowContextHelpButtonHint, False)\n\n        self.cb_on_top = QtWidgets.QCheckBox("Always on top")\n        self.cb_on_top.setChecked(parent.settings["always_on_top"])\n\n        self.alpha_slider = QtWidgets.QSlider(QtCore.Qt.Horizontal)\n        self.alpha_slider.setRange(80, 255)\n        self.alpha_slider.setValue(parent.settings["bg_alpha"])\n\n        self.font_spin = QtWidgets.QSpinBox()\n        self.font_spin.setRange(10, 36)\n        self.font_spin.setValue(parent.settings["font_size"])\n\n        self.w_spin = QtWidgets.QSpinBox()\n        self.w_spin.setRange(240, 900)\n        self.w_spin.setValue(parent.settings["width"])\n        self.h_spin = QtWidgets.QSpinBox()\n        self.h_spin.setRange(120, 600)\n        self.h_spin.setValue(parent.settings["height"])\n\n        btn_quick_start = QtWidgets.QPushButton("Quick start guide")\n        btn_quick_start.clicked.connect(parent.open_quick_start)\n        btn_help = QtWidgets.QPushButton("?")\n        btn_help.setFixedWidth(32)\n        btn_help.setToolTip("Open the quick start guide")\n        btn_help.clicked.connect(parent.open_quick_start)\n\n        btn_reset_data = QtWidgets.QPushButton("Reset data (clear memory)")\n        btn_reset_data.clicked.connect(parent.reset_all_data)\n\n        btn_apply = QtWidgets.QPushButton("Apply")\n        btn_apply.clicked.connect(self.apply)\n        btn_close = QtWidgets.QPushButton("Close")\n        btn_close.clicked.connect(self.close)\n\n        form = QtWidgets.QFormLayout()\n        form.addRow(self.cb_on_top)\n        form.addRow("Background opacity", self.alpha_slider)\n        form.addRow("Font size", self.font_spin)\n\n        size_row = QtWidgets.QHBoxLayout()\n        size_row.addWidget(QtWidgets.QLabel("W"))\n        size_row.addWidget(self.w_spin)\n        size_row.addSpacing(12)\n        size_row.addWidget(QtWidgets.QLabel("H"))\n        size_row.addWidget(self.h_spin)\n        form.addRow("Overlay size", size_row)\n\n        bottom = QtWidgets.QHBoxLayout()\n        bottom.addWidget(btn_help)\n        bottom.addWidget(btn_quick_start)\n        bottom.addWidget(btn_reset_data)\n        bottom.addStretch(1)\n        bottom.addWidget(btn_apply)\n        bottom.addWidget(btn_close)\n\n        root = QtWidgets.QVBoxLayout(self)\n        root.addLayout(form)\n        root.addLayout(bottom)\n\n        # Force light controls for readability regardless of OS theme.\n        self.setStyleSheet(\n            """\n            QDialog {\n                background-color: white;\n                color: black;\n            }\n            QLabel, QCheckBox {\n                color: black;\n                background: transparent;\n            }\n            QSlider, QSpinBox, QPushButton {\n                background-color: white;\n                color: black;\n            }\n            """\n        )\n\n    def apply(self):\n        self.parent_overlay.settings["always_on_top"] = self.cb_on_top.isChecked()\n        self.parent_overlay.settings["bg_alpha"] = int(self.alpha_slider.value())\n        self.parent_overlay.settings["font_size"] = int(self.font_spin.value())\n        self.parent_overlay.settings["width"] = int(self.w_spin.value())\n        self.parent_overlay.settings["height"] = int(self.h_spin.value())\n        self.parent_overlay.apply_settings()\n        self.parent_overlay.save_settings()\n\n\nclass OverlayUI(QtWidgets.QWidget):\n    """Transparent HUD with mini menu (settings/info), updated at 10 Hz."""\n\n    def __init__(self, state: dict, state_lock: threading.Lock):\n        super().__init__()\n        self.state = state\n        self.state_lock = state_lock\n        self.drag_origin: Optional[QtCore.QPoint] = None\n        self.settings = self.load_settings()\n        self.model_ref = TireMLModel(DataStorage(MODEL_PATH))\n\n        self.label = QtWidgets.QLabel(self)\n        self.label.setAlignment(QtCore.Qt.AlignLeft | QtCore.Qt.AlignTop)\n        self.label.setAttribute(QtCore.Qt.WA_TransparentForMouseEvents, True)\n\n        self.btn_info = QtWidgets.QPushButton("ℹ", self)\n        self.btn_info.setFixedWidth(28)\n        self.btn_info.clicked.connect(self.open_info)\n\n        self.btn_settings = QtWidgets.QPushButton("⚙", self)\n        self.btn_settings.setFixedWidth(28)\n        self.btn_settings.clicked.connect(self.open_settings)\n\n        self.btn_close_overlay = QtWidgets.QPushButton("✕", self)\n        self.btn_close_overlay.setFixedWidth(28)\n        self.btn_close_overlay.clicked.connect(QtWidgets.QApplication.quit)\n\n        top_row = QtWidgets.QHBoxLayout()\n        top_row.addStretch(1)\n        top_row.addWidget(self.btn_info)\n        top_row.addWidget(self.btn_settings)\n        top_row.addWidget(self.btn_close_overlay)\n\n        layout = QtWidgets.QVBoxLayout(self)\n        layout.addLayout(top_row)\n        layout.addWidget(self.label)\n        layout.setContentsMargins(6, 6, 6, 6)\n        self.setLayout(layout)\n\n        self.info_dialog = InfoDialog(self)\n        self.quick_start_dialog = QuickStartDialog(self)\n        self.settings_dialog = SettingsDialog(self)\n\n        self.apply_settings()\n\n        self.timer = QtCore.QTimer(self)\n        self.timer.timeout.connect(self.refresh)\n        self.timer.start(100)  # 10 Hz\n\n    @staticmethod\n    def _color_for_value(v: float) -> str:\n        if v > 80.0:\n            return "#7CFC00"\n        if v >= 65.0:\n            return "#FFD700"\n        return "#FF4C4C"\n\n    @staticmethod\n    def _default_settings() -> dict:\n        return {\n            "always_on_top": True,\n            "bg_alpha": 160,\n            "font_size": 18,\n            "width": 340,\n            "height": 220,\n            "x": 120,\n            "y": 120,\n        }\n\n    def load_settings(self) -> dict:\n        cfg = self._default_settings()\n        if os.path.exists(SETTINGS_PATH):\n            try:\n                with open(SETTINGS_PATH, "r", encoding="utf-8") as f:\n                    loaded = json.load(f)\n                if isinstance(loaded, dict):\n                    cfg.update(loaded)\n            except Exception:\n                pass\n        return cfg\n\n    def save_settings(self):\n        try:\n            with open(SETTINGS_PATH + ".tmp", "w", encoding="utf-8") as f:\n                json.dump(self.settings, f, indent=2)\n            os.replace(SETTINGS_PATH + ".tmp", SETTINGS_PATH)\n        except Exception:\n            pass\n\n    def apply_settings(self):\n        flags = QtCore.Qt.FramelessWindowHint | QtCore.Qt.Tool\n        if self.settings["always_on_top"]:\n            flags |= QtCore.Qt.WindowStaysOnTopHint\n        self.setWindowFlags(flags)\n        self.setAttribute(QtCore.Qt.WA_TranslucentBackground, True)\n        self.setStyleSheet("background: transparent;")\n\n        font_size = int(self.settings["font_size"])\n        alpha = int(self.settings["bg_alpha"])\n        self.label.setStyleSheet(\n            f"""\n            QLabel {{\n                color: white;\n                font-family: Consolas, monospace;\n                font-size: {font_size}px;\n                font-weight: bold;\n                background-color: rgba(0, 0, 0, {alpha});\n                border-radius: 10px;\n                padding: 10px;\n            }}\n            """\n        )\n        self.resize(int(self.settings["width"]), int(self.settings["height"]))\n        self.move(int(self.settings["x"]), int(self.settings["y"]))\n        self.show()\n\n    def open_info(self):\n        with self.state_lock:\n            key = self.state.get("key", "unknown")\n            connected = self.state.get("connected", False)\n            temp = float(self.state.get("track_temp", 0.0))\n            air = float(self.state.get("air_temp", 0.0))\n            humidity = float(self.state.get("humidity", 0.0))\n            model_conf = float(self.state.get("model_confidence", 0.0))\n            samples = int(self.state.get("sample_count", 0))\n\n        msg = (\n            f"Connection: {\'Connected\' if connected else \'Disconnected\'}\\n"\n            f"Dataset key: {key}\\n"\n            f"Track temp: {temp:.1f} °C\\n"\n            f"Air temp: {air:.1f} °C\\n"\n            f"Humidity: {humidity:.1f} %\\n"\n            f"Samples: {samples}\\n"\n            f"Model confidence: {model_conf:.1%}\\n\\n"\n        )\n        self.model_ref.load_rls(str(key))\n        msg += self.model_ref.get_coefficients_report(str(key))\n        self.info_dialog.set_info(msg)\n        self.info_dialog.show()\n        self.info_dialog.raise_()\n\n    def open_settings(self):\n        self.settings_dialog.show()\n        self.settings_dialog.raise_()\n\n    def open_quick_start(self):\n        self.quick_start_dialog.show()\n        self.quick_start_dialog.raise_()\n\n    def refresh(self):\n        with self.state_lock:\n            tread = dict(self.state.get("tread", {t: 100.0 for t in TIRE_KEYS}))\n            connected = bool(self.state.get("connected", False))\n            track_name = str(self.state.get("track_name", "") or "-")\n            track_config = str(self.state.get("track_config", "") or "-")\n            car_path = str(self.state.get("car_path", "") or "-")\n            estimate_ready = bool(self.state.get("estimate_ready", False))\n\n        lines = []\n        if estimate_ready:\n            lines.extend(\n                [\n                    f"<span style=\'color:{self._color_for_value(tread.get(\'lf\', 100.0))}\'>LF {tread.get(\'lf\', 100.0):5.1f}%</span>",\n                    f"<span style=\'color:{self._color_for_value(tread.get(\'rf\', 100.0))}\'>RF {tread.get(\'rf\', 100.0):5.1f}%</span>",\n                    f"<span style=\'color:{self._color_for_value(tread.get(\'lr\', 100.0))}\'>LR {tread.get(\'lr\', 100.0):5.1f}%</span>",\n                    f"<span style=\'color:{self._color_for_value(tread.get(\'rr\', 100.0))}\'>RR {tread.get(\'rr\', 100.0):5.1f}%</span>",\n                ]\n            )\n\n        lines.extend(\n            [\n                f"<span style=\'color:#B8E0FF\'>Track: {track_name} ({track_config})</span>",\n                f"<span style=\'color:#B8E0FF\'>Car: {car_path}</span>",\n                f"<span style=\'color:#FFD166\'>Model confidence: {self.state.get(\'model_confidence\', 0.0):.0%}</span>",\n                f"<span style=\'color:{\'#7CFC00\' if connected else \'#FF4C4C\'}\'>SDK: {\'ONLINE\' if connected else \'OFFLINE\'}</span>",\n            ]\n        )\n        self.label.setText("<br>".join(lines))\n\n    def reset_all_data(self):\n        confirm_box = self._build_light_message_box(\n            icon=QtWidgets.QMessageBox.Warning,\n            title="Reset data",\n            text="This will clear learned tire model data and current session memory. Continue?",\n            buttons=QtWidgets.QMessageBox.Yes | QtWidgets.QMessageBox.No,\n            default_button=QtWidgets.QMessageBox.No,\n        )\n        if confirm_box.exec_() != QtWidgets.QMessageBox.Yes:\n            return\n\n        # Clear persisted model samples.\n        for path in (MODEL_PATH, MODEL_PATH + ".tmp"):\n            try:\n                if os.path.exists(path):\n                    os.remove(path)\n            except Exception:\n                pass\n\n        # Reset runtime overlay state.\n        with self.state_lock:\n            self.state.update(\n                tread={t: 100.0 for t in TIRE_KEYS},\n                wear_per_lap={t: 0.0 for t in TIRE_KEYS},\n                key="",\n                model_confidence=0.0,\n                sample_count=0,\n                estimate_ready=False,\n                reset_requested=True,\n            )\n\n        done_box = self._build_light_message_box(\n            icon=QtWidgets.QMessageBox.Information,\n            title="Reset complete",\n            text="All learned data was cleared.",\n            buttons=QtWidgets.QMessageBox.Ok,\n            default_button=QtWidgets.QMessageBox.Ok,\n        )\n        done_box.exec_()\n\n    def _build_light_message_box(\n        self,\n        icon: QtWidgets.QMessageBox.Icon,\n        title: str,\n        text: str,\n        buttons: QtWidgets.QMessageBox.StandardButtons,\n        default_button: QtWidgets.QMessageBox.StandardButton,\n    ) -> QtWidgets.QMessageBox:\n        box = QtWidgets.QMessageBox(self)\n        box.setIcon(icon)\n        box.setWindowTitle(title)\n        box.setText(text)\n        box.setStandardButtons(buttons)\n        box.setDefaultButton(default_button)\n        box.setStyleSheet(\n            """\n            QMessageBox {\n                background-color: white;\n                color: black;\n            }\n            QLabel {\n                color: black;\n                background: transparent;\n            }\n            QPushButton {\n                background-color: white;\n                color: black;\n                border: 1px solid #BDBDBD;\n                padding: 4px 10px;\n                min-width: 72px;\n            }\n            QPushButton:hover {\n                background-color: #F2F2F2;\n            }\n            """\n        )\n        return box\n\n    def mousePressEvent(self, e: QtGui.QMouseEvent):\n        if e.button() == QtCore.Qt.LeftButton:\n            self.drag_origin = e.globalPos() - self.frameGeometry().topLeft()\n            e.accept()\n\n    def mouseMoveEvent(self, e: QtGui.QMouseEvent):\n        if self.drag_origin is not None and (e.buttons() & QtCore.Qt.LeftButton):\n            self.move(e.globalPos() - self.drag_origin)\n            e.accept()\n\n    def mouseReleaseEvent(self, e: QtGui.QMouseEvent):\n        if e.button() == QtCore.Qt.LeftButton:\n            self.drag_origin = None\n            self.settings["x"] = int(self.x())\n            self.settings["y"] = int(self.y())\n            self.save_settings()\n            e.accept()\n\n\nclass MainApp:\n    """Application coordinator: starts telemetry/model threads and Qt UI."""\n\n    def __init__(self):\n        self.stop_event = threading.Event()\n        self.telemetry_queue: queue.Queue = queue.Queue(maxsize=1200)\n        self.state_lock = threading.Lock()\n        self.state = {\n            "tread": {t: 100.0 for t in TIRE_KEYS},\n            "wear_per_lap": {t: 0.0 for t in TIRE_KEYS},\n            "estimate_ready": False,\n            "connected": False,\n            "key": "",\n            "model_confidence": 0.0,\n            "sample_count": 0,\n            "track_temp": 0.0,\n            "air_temp": 0.0,\n            "humidity": 0.0,\n            "track_name": "",\n            "track_config": "",\n            "car_path": "",\n            "reset_requested": False,\n            "updated_at": time.time(),\n        }\n\n        self.telemetry_thread = TelemetryReader(self.telemetry_queue, self.stop_event)\n        self.model_thread = ModelWorker(self.telemetry_queue, self.state, self.state_lock, self.stop_event)\n\n    def start(self) -> int:\n        self.telemetry_thread.start()\n        self.model_thread.start()\n\n        app = QtWidgets.QApplication([])\n        overlay = OverlayUI(self.state, self.state_lock)\n        overlay.show()\n\n        def handle_signal(*_):\n            self.shutdown()\n            app.quit()\n\n        signal.signal(signal.SIGINT, handle_signal)\n        signal.signal(signal.SIGTERM, handle_signal)\n\n        code = app.exec_()\n        self.shutdown()\n        return int(code)\n\n    def shutdown(self):\n        if self.stop_event.is_set():\n            return\n        self.stop_event.set()\n        for t in (self.telemetry_thread, self.model_thread):\n            if t.is_alive():\n                t.join(timeout=2.0)\n\n\ndef main():\n    app = MainApp()\n    raise SystemExit(app.start())\n\n\nif __name__ == "__main__":\n    main()\n',
    'traction': '#!/usr/bin/env python3\n"""Standalone Tkinter traction-circle overlay for iRacing telemetry.\n\nFeatures\n- Real-time traction circle from LongAccel and LatAccel.\n- Learns reference grip usage per LapDistPct bin from configurable coaching laps.\n- Detects robust underuse opportunities with session coaching insights.\n"""\n\nfrom __future__ import annotations\n\nimport math\nimport os\nimport statistics\nimport tkinter as tk\nfrom collections import deque\nfrom dataclasses import dataclass\nfrom tkinter import filedialog, ttk\nfrom typing import Any, Deque, List, Optional, Sequence, Tuple\n\nimport irsdk\n\nG_CONSTANT = 9.80665\nUPDATE_MS = 60\nBINS_PER_LAP = 200\nMIN_REFERENCE_G = 0.75\nUNDERUSE_MARGIN = 0.12\nMIN_SEGMENT_BINS = 3\nMIN_SAMPLES_PER_BIN = 5\nMAX_LAP_HISTORY = 1000\nRECENT_VALID_LAPS = 5\nTOGGLE_MODE_KEY = "m"\nDEFAULT_LAPS_FOR_FEEDBACK = 5\nQUICKSTART_TEXT = """Quickstart\n1. Join a session and click Drive so telemetry starts streaming.\n2. Drive a few representative laps while keeping the car on track.\n3. Set how many completed laps should be collected before tips start.\n4. Decide whether those laps must be incident-free only or if every lap should count.\n5. Use the coaching panel to compare your current grip use to the learned or IBT reference.\n6. Press M to switch between compact and detailed coaching summaries.\n"""\n\n\n@dataclass\nclass LapData:\n    lap_number: int\n    lap_time: float\n    valid: bool\n    bins: List[float]\n    long_bins: List[float]\n    lat_bins: List[float]\n\n\n@dataclass\nclass UnderuseSegment:\n    start_percent: float\n    end_percent: float\n    peak_percent: float\n    reference_g: float\n    achieved_g: float\n    delta_g: float\n    severity: str\n    phase: str\n    recommendation: str\n    trend: str\n    consistency: float\n    confidence: bool\n\n\nclass TractionCircleOverlay:\n    def __init__(self) -> None:\n        self.ir = irsdk.IRSDK()\n\n        self.root = tk.Tk()\n        self.root.title("Traction Circle Limiter")\n        self.root.geometry("900x540")\n        self.root.configure(bg="#101418")\n        self.root.attributes("-topmost", True)\n\n        self.status_var = tk.StringVar(value="Connecting to iRacing...")\n        self.header_var = tk.StringVar(value="Car: -- | Track: -- | Session: -- | Valid laps: 0")\n        self.current_var = tk.StringVar(value="Current: --")\n        self.limit_var = tk.StringVar(value="Estimated limit: --")\n        self.quality_var = tk.StringVar(value="Valid laps used: 0 | Invalid laps discarded: 0 | Outliers removed: 0")\n        self.summary_var = tk.StringVar(value="Collecting lap data...")\n        self.mode_var = tk.StringVar(value="Mode: compact")\n        self.reference_var = tk.StringVar(value="Reference: live adaptive")\n\n        self.current_lap_num: Optional[int] = None\n        self.current_lap_bins: List[float] = [0.0] * BINS_PER_LAP\n        self.current_lap_long_bins: List[float] = [0.0] * BINS_PER_LAP\n        self.current_lap_lat_bins: List[float] = [0.0] * BINS_PER_LAP\n        self.current_lap_valid = True\n\n        self.lap_history: Deque[LapData] = deque(maxlen=MAX_LAP_HISTORY)\n        self.invalid_laps_count = 0\n        self.outliers_removed_last = 0\n        self.bin_confidence: List[bool] = [False] * BINS_PER_LAP\n\n        self.context_key = ""\n        self.current_track = "--"\n        self.current_car = "--"\n        self.current_session = "--"\n\n        self.recent_peaks: Deque[float] = deque(maxlen=300)\n        self.estimated_limit_g = 1.8\n\n        self.compact_mode = True\n        self.external_reference_bins: Optional[List[float]] = None\n        self.external_reference_path: Optional[str] = None\n\n        self.laps_for_feedback_var = tk.IntVar(value=DEFAULT_LAPS_FOR_FEEDBACK)\n        self.incident_free_only_var = tk.BooleanVar(value=True)\n        self.quickstart_visible_var = tk.BooleanVar(value=True)\n\n        self._build_ui()\n        self._refresh_feedback_settings()\n        self.root.bind(f"<{TOGGLE_MODE_KEY}>", self._toggle_mode)\n        self.root.bind(f"<{TOGGLE_MODE_KEY.upper()}>", self._toggle_mode)\n\n    def _build_ui(self) -> None:\n        container = ttk.Frame(self.root, padding=10)\n        container.pack(fill="both", expand=True)\n\n        controls = ttk.Frame(container)\n        controls.pack(fill="x", pady=(0, 8))\n\n        ttk.Label(controls, textvariable=self.status_var, foreground="#4b5563").pack(side="left")\n        ttk.Label(controls, text=f"  Toggle: \'{TOGGLE_MODE_KEY.upper()}\'", foreground="#4b5563").pack(side="left")\n        ttk.Button(controls, text="Load IBT", command=self._load_ibt_reference).pack(side="right")\n        ttk.Button(controls, text="Use Live", command=self._clear_ibt_reference).pack(side="right", padx=(0, 6))\n        ttk.Checkbutton(controls, text="Show quickstart", variable=self.quickstart_visible_var, command=self._toggle_quickstart).pack(side="right", padx=(0, 10))\n\n        ttk.Label(container, textvariable=self.header_var, font=("Segoe UI", 10, "bold")).pack(anchor="w", pady=(0, 8))\n\n        self.quickstart_frame = ttk.LabelFrame(container, text="Quickstart", padding=10)\n        self.quickstart_frame.pack(fill="x", pady=(0, 8))\n        ttk.Label(\n            self.quickstart_frame,\n            text=QUICKSTART_TEXT.strip(),\n            justify="left",\n            wraplength=840,\n            font=("Segoe UI", 9),\n        ).pack(anchor="w")\n\n        settings = ttk.LabelFrame(container, text="Coaching settings", padding=10)\n        settings.pack(fill="x", pady=(0, 8))\n\n        ttk.Label(settings, text="Start tips after this many laps:").grid(row=0, column=0, sticky="w")\n        self.laps_spinbox = ttk.Spinbox(\n            settings,\n            from_=1,\n            to=50,\n            width=5,\n            textvariable=self.laps_for_feedback_var,\n            command=self._refresh_feedback_settings,\n        )\n        self.laps_spinbox.grid(row=0, column=1, sticky="w", padx=(8, 16))\n        self.laps_spinbox.bind("<KeyRelease>", self._refresh_feedback_settings)\n        self.laps_spinbox.bind("<<Increment>>", self._refresh_feedback_settings)\n        self.laps_spinbox.bind("<<Decrement>>", self._refresh_feedback_settings)\n\n        ttk.Checkbutton(\n            settings,\n            text="Only count incident-free laps for learning and tips",\n            variable=self.incident_free_only_var,\n            command=self._refresh_feedback_settings,\n        ).grid(row=1, column=0, columnspan=2, sticky="w", pady=(8, 0))\n\n        self.settings_hint_var = tk.StringVar(value="Tips start after 5 incident-free lap(s).")\n        ttk.Label(settings, textvariable=self.settings_hint_var, foreground="#4b5563").grid(\n            row=2, column=0, columnspan=2, sticky="w", pady=(8, 0)\n        )\n\n        body = ttk.Frame(container)\n        body.pack(fill="both", expand=True)\n\n        self.canvas = tk.Canvas(\n            body,\n            width=400,\n            height=400,\n            bg="#0b0f13",\n            highlightthickness=1,\n            highlightbackground="#2b3540",\n        )\n        self.canvas.pack(side="left", padx=(0, 10), fill="both", expand=False)\n\n        right = ttk.Frame(body)\n        right.pack(side="left", fill="both", expand=True)\n\n        ttk.Label(right, text="Real-time grip usage", font=("Segoe UI", 12, "bold")).pack(anchor="w")\n        ttk.Label(right, textvariable=self.current_var, font=("Consolas", 10)).pack(anchor="w", pady=(8, 0))\n        ttk.Label(right, textvariable=self.limit_var, font=("Consolas", 10)).pack(anchor="w")\n        ttk.Label(right, textvariable=self.quality_var, font=("Consolas", 9), foreground="#4b5563").pack(anchor="w", pady=(2, 0))\n\n        ttk.Separator(right).pack(fill="x", pady=10)\n\n        ttk.Label(right, textvariable=self.mode_var, font=("Segoe UI", 10, "bold")).pack(anchor="w")\n        ttk.Label(right, textvariable=self.reference_var, font=("Segoe UI", 9), foreground="#4b5563").pack(anchor="w")\n        self.summary_label = ttk.Label(\n            right,\n            textvariable=self.summary_var,\n            justify="left",\n            font=("Consolas", 10),\n            wraplength=420,\n        )\n        self.summary_label.pack(anchor="w", pady=(6, 0))\n\n    @staticmethod\n    def _safe_float(value: object, default: float = 0.0) -> float:\n        try:\n            parsed = float(value)\n        except (TypeError, ValueError):\n            return default\n        if not math.isfinite(parsed):\n            return default\n        return parsed\n\n    def _read_var(self, name: str, default: object = None) -> object:\n        try:\n            return self.ir[name]\n        except Exception:\n            return default\n\n    @staticmethod\n    def _bin_index(lap_dist_pct: float) -> int:\n        normalized = max(0.0, min(0.999999, lap_dist_pct))\n        return int(normalized * BINS_PER_LAP)\n\n    @staticmethod\n    def _get_nested(data: object, *path: object) -> object:\n        cur = data\n        for item in path:\n            if isinstance(item, int):\n                if not isinstance(cur, list) or item < 0 or item >= len(cur):\n                    return None\n                cur = cur[item]\n                continue\n            if not isinstance(cur, dict):\n                return None\n            cur = cur.get(item)\n            if cur is None:\n                return None\n        return cur\n\n    def _detect_context(self) -> Tuple[str, str, str, str]:\n        weekend = self._read_var("WeekendInfo", {})\n        driver_info = self._read_var("DriverInfo", {})\n        session_info = self._read_var("SessionInfo", {})\n        driver_car_idx = int(self._safe_float(self._read_var("DriverCarIdx", 0)))\n\n        track_id = self._get_nested(weekend, "TrackID")\n        track_name = self._get_nested(weekend, "TrackName")\n        track_cfg = self._get_nested(weekend, "TrackConfigName")\n        track_value = track_id if track_id not in (None, "") else (track_name or track_cfg or "unknown")\n        track_display = track_name or track_cfg or str(track_value)\n\n        car_id = self._get_nested(driver_info, "Drivers", driver_car_idx, "CarID")\n        car_path = self._get_nested(driver_info, "Drivers", driver_car_idx, "CarPath")\n        car_screen = self._get_nested(driver_info, "Drivers", driver_car_idx, "CarScreenName")\n        car_value = car_id if car_id not in (None, "") else (car_path or "unknown")\n        car_display = car_screen or car_path or str(car_value)\n\n        session_num = int(self._safe_float(self._read_var("SessionNum", 0)))\n        session_name = self._get_nested(session_info, "Sessions", session_num, "SessionName")\n        session_display = str(session_name or "Unknown")\n\n        context_key = f"track:{track_value}|car:{car_value}"\n        return context_key, str(track_display), str(car_display), session_display\n\n    def _reset_for_new_context(self) -> None:\n        self.current_lap_num = None\n        self.current_lap_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_long_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_lat_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_valid = True\n        self.lap_history.clear()\n        self.invalid_laps_count = 0\n        self.outliers_removed_last = 0\n        self.bin_confidence = [False] * BINS_PER_LAP\n\n    def _is_offtrack(self, driver_car_idx: int) -> bool:\n        surfaces = self._read_var("CarIdxTrackSurface", [])\n        if not isinstance(surfaces, list) or driver_car_idx < 0 or driver_car_idx >= len(surfaces):\n            return False\n        val = surfaces[driver_car_idx]\n        if isinstance(val, str):\n            return "offtrack" in val.lower()\n        try:\n            numeric = int(val)\n        except (TypeError, ValueError):\n            return False\n        return numeric == 1\n\n    def _finalize_current_lap(self, next_lap_num: int) -> None:\n        if self.current_lap_num is None:\n            self.current_lap_num = next_lap_num\n            return\n        if next_lap_num == self.current_lap_num:\n            return\n\n        if self.current_lap_num < 0:\n            self.current_lap_num = next_lap_num\n            return\n\n        lap_time = self._safe_float(self._read_var("LapLastLapTime", 0.0), default=0.0)\n        lap_data = LapData(\n            lap_number=self.current_lap_num,\n            lap_time=lap_time,\n            valid=self.current_lap_valid,\n            bins=self.current_lap_bins.copy(),\n            long_bins=self.current_lap_long_bins.copy(),\n            lat_bins=self.current_lap_lat_bins.copy(),\n        )\n        self.lap_history.append(lap_data)\n        if not lap_data.valid:\n            self.invalid_laps_count += 1\n\n        self.current_lap_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_long_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_lat_bins = [0.0] * BINS_PER_LAP\n        self.current_lap_valid = True\n        self.current_lap_num = next_lap_num\n\n    def _update_lap_storage(\n        self,\n        lap_num: int,\n        lap_dist_pct: float,\n        g_total: float,\n        long_g: float,\n        lat_g: float,\n        offtrack: bool,\n    ) -> None:\n        self._finalize_current_lap(lap_num)\n        if offtrack:\n            self.current_lap_valid = False\n\n        idx = self._bin_index(lap_dist_pct)\n        if g_total > self.current_lap_bins[idx]:\n            self.current_lap_bins[idx] = g_total\n            self.current_lap_long_bins[idx] = long_g\n            self.current_lap_lat_bins[idx] = lat_g\n\n    @staticmethod\n    def _iqr_filter(values: Sequence[float]) -> Tuple[List[float], int]:\n        if len(values) < 4:\n            return list(values), 0\n        sorted_vals = sorted(values)\n        q1, _, q3 = statistics.quantiles(sorted_vals, n=4, method="inclusive")\n        iqr = q3 - q1\n        lower = q1 - 1.5 * iqr\n        upper = q3 + 1.5 * iqr\n        filtered = [v for v in sorted_vals if lower <= v <= upper]\n        return filtered, len(sorted_vals) - len(filtered)\n\n    def _compute_reference_by_bin(self, valid_laps: Sequence[LapData]) -> List[float]:\n        reference: List[float] = [0.0] * BINS_PER_LAP\n        self.outliers_removed_last = 0\n        self.bin_confidence = [False] * BINS_PER_LAP\n        if not valid_laps:\n            return reference\n\n        for i in range(BINS_PER_LAP):\n            values = [lap.bins[i] for lap in valid_laps if lap.bins[i] > 0.05]\n            if not values:\n                continue\n            filtered, removed = self._iqr_filter(values)\n            self.outliers_removed_last += removed\n            if len(filtered) < MIN_SAMPLES_PER_BIN:\n                continue\n            filtered.sort()\n            idx = min(len(filtered) - 1, int(round((len(filtered) - 1) * 0.9)))\n            reference[i] = filtered[idx]\n            self.bin_confidence[i] = True\n        return reference\n\n    @staticmethod\n    def _read_ibt_series(ibt: Any, name: str) -> List[float]:\n        for method_name in ("get_all", "get"):\n            method = getattr(ibt, method_name, None)\n            if callable(method):\n                try:\n                    values = method(name)\n                except Exception:\n                    continue\n                if values is not None:\n                    return [TractionCircleOverlay._safe_float(v, default=0.0) for v in list(values)]\n\n        try:\n            values = ibt[name]  # type: ignore[index]\n            return [TractionCircleOverlay._safe_float(v, default=0.0) for v in list(values)]\n        except Exception:\n            return []\n\n    def _reference_from_ibt(self, file_path: str) -> Optional[List[float]]:\n        ibt_reader = getattr(irsdk, "IBT", None)\n        if ibt_reader is None:\n            self.status_var.set("Your irsdk build does not expose IBT reader support.")\n            return None\n\n        try:\n            ibt = ibt_reader()\n            opened = ibt.open(file_path)\n        except Exception as exc:\n            self.status_var.set(f"Failed to open IBT: {exc}")\n            return None\n\n        if opened is False:\n            self.status_var.set("Failed to open IBT file.")\n            return None\n\n        lap_dist = self._read_ibt_series(ibt, "LapDistPct")\n        long_accel = self._read_ibt_series(ibt, "LongAccel")\n        lat_accel = self._read_ibt_series(ibt, "LatAccel")\n        if not lap_dist or not long_accel or not lat_accel:\n            self.status_var.set("IBT is missing LapDistPct / LongAccel / LatAccel.")\n            return None\n\n        sample_count = min(len(lap_dist), len(long_accel), len(lat_accel))\n        bins = [0.0] * BINS_PER_LAP\n        for i in range(sample_count):\n            idx = self._bin_index(self._safe_float(lap_dist[i], default=0.0))\n            long_g = self._safe_float(long_accel[i], default=0.0) / G_CONSTANT\n            lat_g = self._safe_float(lat_accel[i], default=0.0) / G_CONSTANT\n            total_g = math.hypot(long_g, lat_g)\n            if total_g > bins[idx]:\n                bins[idx] = total_g\n\n        if max(bins, default=0.0) < MIN_REFERENCE_G:\n            self.status_var.set("IBT loaded, but no meaningful grip reference could be built.")\n            return None\n        return bins\n\n    def _load_ibt_reference(self) -> None:\n        file_path = filedialog.askopenfilename(\n            title="Load IBT reference",\n            filetypes=[("iRacing telemetry", "*.ibt"), ("All files", "*.*")],\n        )\n        if not file_path:\n            return\n\n        bins = self._reference_from_ibt(file_path)\n        if bins is None:\n            return\n\n        self.external_reference_bins = bins\n        self.external_reference_path = file_path\n        self.reference_var.set(f"Reference: IBT {os.path.basename(file_path)}")\n        lap_target = self._feedback_lap_target()\n        lap_label = "incident-free" if self.incident_free_only_var.get() else "completed"\n        self.status_var.set(f"IBT reference loaded. Feedback starts after {lap_target} {lap_label} lap(s).")\n\n    def _clear_ibt_reference(self) -> None:\n        self.external_reference_bins = None\n        self.external_reference_path = None\n        self.reference_var.set("Reference: live adaptive")\n        lap_label = "incident-free" if self.incident_free_only_var.get() else "completed"\n        self.status_var.set(f"Using live adaptive reference from your {lap_label} laps.")\n\n    @staticmethod\n    def _phase_and_recommendation(neg_long: float, lat: float, pos_long: float) -> Tuple[str, str]:\n        if neg_long > max(lat, pos_long):\n            return "Entry", "You are leaving grip on the table while braking. Try braking 5-10m later, or ease off peak brake pressure so rotation stays smooth."\n        if lat >= max(neg_long, pos_long):\n            return "Mid-corner", "You can likely carry a bit more minimum speed. Release the brakes earlier, let the car rotate, and aim for a cleaner apex."\n        return "Exit", "There is room on corner exit. Start feeding throttle a touch earlier and build it progressively to avoid wheelspin."\n\n    @staticmethod\n    def _severity_label(delta_g: float) -> str:\n        if delta_g >= 0.25:\n            return "high"\n        if delta_g >= 0.12:\n            return "medium"\n        return "low"\n\n    @staticmethod\n    def _trend_label(values: Sequence[float]) -> str:\n        if len(values) < 3:\n            return "stable"\n        split = max(1, len(values) // 2)\n        first = statistics.mean(values[:split])\n        second = statistics.mean(values[split:])\n        if second - first > 0.03:\n            return "improving"\n        if second - first < -0.03:\n            return "declining"\n        return "stable"\n\n    @staticmethod\n    def _lapdist_hint(start_percent: float, end_percent: float, peak_percent: float) -> str:\n        def phase_label(value: float) -> str:\n            if value < 1.0 / 3.0:\n                return "start"\n            if value < 2.0 / 3.0:\n                return "middle"\n            return "end"\n\n        start_pct = start_percent * 100.0\n        end_pct = end_percent * 100.0\n        peak_pct = peak_percent * 100.0\n        return (\n            f"LapDistPct {start_pct:.1f}%→{end_pct:.1f}% "\n            f"(peak at {peak_pct:.1f}% / {phase_label(peak_percent)} of lap)"\n        )\n\n    def _detect_underuse_segments(self, valid_laps: Sequence[LapData], reference: Sequence[float]) -> List[UnderuseSegment]:\n        if not valid_laps:\n            return []\n\n        recent = list(valid_laps[-RECENT_VALID_LAPS:])\n        achieved: List[float] = [0.0] * BINS_PER_LAP\n        for i in range(BINS_PER_LAP):\n            values = [lap.bins[i] for lap in recent if lap.bins[i] > 0.05]\n            if values:\n                achieved[i] = statistics.median(values)\n\n        segments: List[Tuple[int, int]] = []\n        start = -1\n        for i in range(BINS_PER_LAP):\n            ref = reference[i]\n            ach = achieved[i]\n            confident = self.bin_confidence[i]\n            is_under = confident and ref >= MIN_REFERENCE_G and ach < ref * (1.0 - UNDERUSE_MARGIN)\n            if is_under and start < 0:\n                start = i\n            if (not is_under or i == BINS_PER_LAP - 1) and start >= 0:\n                end = i if is_under and i == BINS_PER_LAP - 1 else i - 1\n                if end - start + 1 >= MIN_SEGMENT_BINS:\n                    segments.append((start, end))\n                start = -1\n\n        results: List[UnderuseSegment] = []\n        for seg_start, seg_end in segments:\n            best_idx = seg_start\n            best_gap = -1.0\n            for i in range(seg_start, seg_end + 1):\n                gap = reference[i] - achieved[i]\n                if gap > best_gap:\n                    best_gap = gap\n                    best_idx = i\n\n            neg_long = statistics.mean([max(0.0, -lap.long_bins[best_idx]) for lap in recent])\n            lat_mag = statistics.mean([abs(lap.lat_bins[best_idx]) for lap in recent])\n            pos_long = statistics.mean([max(0.0, lap.long_bins[best_idx]) for lap in recent])\n            phase, rec = self._phase_and_recommendation(neg_long, lat_mag, pos_long)\n\n            peak_ref = reference[best_idx]\n            peak_ach = achieved[best_idx]\n            delta = max(0.0, peak_ref - peak_ach)\n\n            under_laps = 0\n            used_laps = 0\n            for lap in valid_laps:\n                val = lap.bins[best_idx]\n                if val <= 0.05:\n                    continue\n                used_laps += 1\n                if val < peak_ref * (1.0 - UNDERUSE_MARGIN / 2.0):\n                    under_laps += 1\n            consistency = (under_laps / used_laps * 100.0) if used_laps else 0.0\n\n            trend_values = [lap.bins[best_idx] for lap in recent if lap.bins[best_idx] > 0.05]\n            trend = self._trend_label(trend_values)\n\n            results.append(\n                UnderuseSegment(\n                    start_percent=seg_start / BINS_PER_LAP,\n                    end_percent=(seg_end + 1) / BINS_PER_LAP,\n                    peak_percent=(best_idx + 0.5) / BINS_PER_LAP,\n                    reference_g=peak_ref,\n                    achieved_g=peak_ach,\n                    delta_g=delta,\n                    severity=self._severity_label(delta),\n                    phase=phase,\n                    recommendation=rec,\n                    trend=trend,\n                    consistency=consistency,\n                    confidence=self.bin_confidence[best_idx],\n                )\n            )\n\n        results.sort(key=lambda s: s.delta_g, reverse=True)\n        return results\n\n    @staticmethod\n    def _format_summary(segments: Sequence[UnderuseSegment], compact_mode: bool, lap_label: str) -> str:\n        if not segments:\n            return f"No clear coaching tips yet. Keep driving {lap_label} laps so the app can learn your baseline."\n\n        top3 = list(segments[:3])\n        lines = [\n            "Top 3 improvement areas (largest grip gap first):",\n            "Tip: Δg is the grip difference between your current pace and the learned reference.",\n        ]\n        for seg in top3:\n            lines.append(\n                f"• Lap {seg.start_percent*100:.1f}% to {seg.end_percent*100:.1f}% | Δ{seg.delta_g:.2f}g | "\n                f"{seg.phase} phase | trend: {seg.trend} | seen in {seg.consistency:.0f}% of {lap_label} laps"\n            )\n            lines.append(f"  ↳ {TractionCircleOverlay._lapdist_hint(seg.start_percent, seg.end_percent, seg.peak_percent)}")\n            lines.append(f"  ↳ What to try next lap: {seg.recommendation}")\n\n        if compact_mode:\n            lines.append("\\nCompact mode: showing only the highest-impact opportunities.")\n            return "\\n".join(lines)\n\n        lines.append("\\nDetailed breakdown:")\n        for seg in segments:\n            confidence_label = "high confidence" if seg.confidence else "low confidence (needs more clean laps)"\n            lines.append(\n                f"- Lap {seg.start_percent*100:.1f}% to {seg.end_percent*100:.1f}% "\n                f"(largest gap near {seg.peak_percent*100:.1f}%): reference {seg.reference_g:.2f}g vs your {seg.achieved_g:.2f}g, "\n                f"so Δ{seg.delta_g:.2f}g ({seg.severity} priority, {confidence_label})."\n            )\n            lines.append(f"  {TractionCircleOverlay._lapdist_hint(seg.start_percent, seg.end_percent, seg.peak_percent)}")\n            lines.append(f"  Why this matters ({seg.phase}): {seg.recommendation}")\n        return "\\n".join(lines)\n\n    def _draw_circle(self, long_g: float, lat_g: float) -> None:\n        self.canvas.delete("all")\n        w = int(self.canvas.winfo_width())\n        h = int(self.canvas.winfo_height())\n        cx, cy = w // 2, h // 2\n        radius = min(w, h) * 0.42\n\n        self.canvas.create_oval(cx - radius, cy - radius, cx + radius, cy + radius, outline="#374151", width=2)\n        self.canvas.create_line(cx - radius, cy, cx + radius, cy, fill="#25303b")\n        self.canvas.create_line(cx, cy - radius, cx, cy + radius, fill="#25303b")\n\n        for frac in (0.25, 0.5, 0.75):\n            rr = radius * frac\n            self.canvas.create_oval(cx - rr, cy - rr, cx + rr, cy + rr, outline="#1f2937")\n\n        limit = max(0.8, self.estimated_limit_g)\n        scale = radius / limit\n\n        dot_x = cx + lat_g * scale\n        dot_y = cy - long_g * scale\n        dot_r = 6\n        self.canvas.create_oval(dot_x - dot_r, dot_y - dot_r, dot_x + dot_r, dot_y + dot_r, fill="#22d3ee", outline="")\n\n        self.canvas.create_text(cx, 16, text="LongAccel (+brake / -throttle)", fill="#9ca3af", font=("Segoe UI", 9))\n        self.canvas.create_text(16, cy, text="Lat", fill="#9ca3af", font=("Segoe UI", 9), angle=90)\n\n    def _toggle_mode(self, _event: object = None) -> None:\n        self.compact_mode = not self.compact_mode\n        self.mode_var.set(f"Mode: {\'compact\' if self.compact_mode else \'detailed\'}")\n\n    def _feedback_lap_target(self) -> int:\n        try:\n            laps = int(self.laps_for_feedback_var.get())\n        except (TypeError, ValueError, tk.TclError):\n            laps = DEFAULT_LAPS_FOR_FEEDBACK\n        laps = max(1, min(50, laps))\n        if self.laps_for_feedback_var.get() != laps:\n            self.laps_for_feedback_var.set(laps)\n        return laps\n\n    def _toggle_quickstart(self) -> None:\n        if self.quickstart_visible_var.get():\n            self.quickstart_frame.pack(fill="x", pady=(0, 8), before=self.canvas.master)\n        else:\n            self.quickstart_frame.pack_forget()\n\n    def _refresh_feedback_settings(self, _event: object = None) -> None:\n        lap_target = self._feedback_lap_target()\n        lap_label = "incident-free" if self.incident_free_only_var.get() else "completed"\n        self.settings_hint_var.set(f"Tips start after {lap_target} {lap_label} lap(s).")\n\n    def _update(self) -> None:\n        connected = self.ir.startup() if not getattr(self.ir, "is_initialized", False) else True\n        if not connected:\n            self.status_var.set("Not connected. Open iRacing and click Drive.")\n            self.current_var.set("Current: --")\n            self.limit_var.set("Estimated limit: --")\n            self.summary_var.set("Waiting for telemetry...")\n            self._draw_circle(0.0, 0.0)\n            self.root.after(400, self._update)\n            return\n\n        self.status_var.set("Connected. Live telemetry active (60 Hz stream / 60 ms refresh).")\n\n        context_key, track_name, car_name, session_name = self._detect_context()\n        if self.context_key and context_key != self.context_key:\n            self._reset_for_new_context()\n        self.context_key = context_key\n        self.current_track = track_name\n        self.current_car = car_name\n        self.current_session = session_name\n\n        long_accel = self._safe_float(self._read_var("LongAccel", 0.0))\n        lat_accel = self._safe_float(self._read_var("LatAccel", 0.0))\n        lap_num = int(self._safe_float(self._read_var("Lap", 0.0)))\n        lap_dist_pct = self._safe_float(self._read_var("LapDistPct", 0.0))\n        driver_idx = int(self._safe_float(self._read_var("DriverCarIdx", 0)))\n\n        long_g = long_accel / G_CONSTANT\n        lat_g = lat_accel / G_CONSTANT\n        g_total = math.hypot(long_g, lat_g)\n\n        self.recent_peaks.append(g_total)\n        if len(self.recent_peaks) > 20:\n            sorted_vals = sorted(self.recent_peaks)\n            self.estimated_limit_g = sorted_vals[int(0.95 * (len(sorted_vals) - 1))]\n\n        offtrack = self._is_offtrack(driver_idx)\n        self._update_lap_storage(lap_num, lap_dist_pct, g_total, long_g, lat_g, offtrack)\n\n        incident_free_only = self.incident_free_only_var.get()\n        coaching_laps = [lap for lap in self.lap_history if lap.valid] if incident_free_only else list(self.lap_history)\n        if self.external_reference_bins is not None:\n            reference = self.external_reference_bins\n            self.outliers_removed_last = 0\n            self.bin_confidence = [v >= MIN_REFERENCE_G for v in reference]\n        else:\n            reference = self._compute_reference_by_bin(coaching_laps)\n\n        lap_target = self._feedback_lap_target()\n        laps_used_label = "incident-free" if incident_free_only else "completed"\n        if len(coaching_laps) < lap_target:\n            laps_left = lap_target - len(coaching_laps)\n            if self.external_reference_bins is not None:\n                segments: List[UnderuseSegment] = []\n                self.summary_var.set(\n                    f"IBT reference is loaded. Drive {laps_left} more {laps_used_label} lap(s), then coaching will compare you against that baseline."\n                )\n            else:\n                segments = self._detect_underuse_segments(coaching_laps, reference)\n        else:\n            segments = self._detect_underuse_segments(coaching_laps, reference)\n\n        usage_pct = (g_total / max(0.5, self.estimated_limit_g)) * 100.0\n        self.current_var.set(\n            f"Current: Long {long_g:+.2f}g | Lat {lat_g:+.2f}g | Total {g_total:.2f}g ({usage_pct:4.0f}%)"\n        )\n        self.limit_var.set(f"Estimated limit: {self.estimated_limit_g:.2f}g")\n        self.quality_var.set(\n            f"Laps used for coaching: {len(coaching_laps)} ({laps_used_label}) | Invalid laps discarded: {self.invalid_laps_count} | "\n            f"Outliers removed: {self.outliers_removed_last}"\n        )\n        self.header_var.set(\n            f"Car: {self.current_car} | Track: {self.current_track} | Session: {self.current_session} | "\n            f"Coaching laps: {len(coaching_laps)}"\n        )\n        self.mode_var.set(f"Mode: {\'compact\' if self.compact_mode else \'detailed\'}")\n        self._refresh_feedback_settings()\n        if len(coaching_laps) >= lap_target or self.external_reference_bins is None:\n            self.summary_var.set(self._format_summary(segments, self.compact_mode, laps_used_label))\n\n        self._draw_circle(long_g, lat_g)\n        self.root.after(UPDATE_MS, self._update)\n\n    def run(self) -> None:\n        self._draw_circle(0.0, 0.0)\n        self._update()\n        self.root.mainloop()\n\n\ndef main() -> int:\n    app = TractionCircleOverlay()\n    app.run()\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n',
}


def _run_embedded_app(app_key: str) -> int:
    source = EMBEDDED_APPS.get(app_key)
    if source is None:
        raise SystemExit(f"Unknown app: {app_key}")

    namespace = {
        '__name__': '__main__',
        '__file__': f'{Path(__file__).stem}::{app_key}',
        "__package__": None,
    }
    exec(compile(source, namespace["__file__"], "exec"), namespace, namespace)
    return 0


class NishizumiSuiteLauncher:
    BG = "#11151c"
    PANEL = "#1a2130"
    PANEL_ALT = "#20293b"
    TEXT = "#f5f7fb"
    MUTED = "#a5afc1"
    ACCENT = "#7fd3ff"
    GOOD = "#90e0a7"
    BAD = "#ff9f9f"

    def __init__(self) -> None:
        self.root = tk.Tk()
        self.root.title("Nishizumi Tools Suite")
        self.root.geometry("540x330")
        self.root.configure(bg=self.BG)
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

        self.processes: Dict[str, subprocess.Popen] = {}
        self.status_vars: Dict[str, tk.StringVar] = {}
        self.launch_buttons: Dict[str, tk.Button] = {}
        self.close_buttons: Dict[str, tk.Button] = {}

        self._build_ui()
        self._poll_processes()

    def _build_ui(self) -> None:
        outer = tk.Frame(self.root, bg=self.BG, padx=16, pady=16)
        outer.pack(fill="both", expand=True)

        tk.Label(
            outer,
            text="Nishizumi Tools Suite",
            font=("Segoe UI", 18, "bold"),
            fg=self.TEXT,
            bg=self.BG,
        ).pack(anchor="w")
        tk.Label(
            outer,
            text="Launch or close any embedded overlay from this single-file control panel.",
            font=("Segoe UI", 10),
            fg=self.MUTED,
            bg=self.BG,
        ).pack(anchor="w", pady=(4, 12))

        for index, (app_key, label) in enumerate(APP_DEFINITIONS, start=1):
            row = tk.Frame(outer, bg=self.PANEL if index % 2 else self.PANEL_ALT, padx=12, pady=10)
            row.pack(fill="x", pady=4)

            text_col = tk.Frame(row, bg=row["bg"])
            text_col.pack(side="left", fill="x", expand=True)

            tk.Label(
                text_col,
                text=label,
                font=("Segoe UI", 11, "bold"),
                fg=self.TEXT,
                bg=row["bg"],
            ).pack(anchor="w")

            status_var = tk.StringVar(value="Closed")
            self.status_vars[app_key] = status_var
            tk.Label(
                text_col,
                textvariable=status_var,
                font=("Segoe UI", 9),
                fg=self.MUTED,
                bg=row["bg"],
            ).pack(anchor="w", pady=(2, 0))

            actions = tk.Frame(row, bg=row["bg"])
            actions.pack(side="right")

            launch_button = tk.Button(
                actions,
                text="Open",
                command=lambda current=app_key: self.launch_app(current),
                bg="#26415d",
                fg=self.TEXT,
                activebackground="#31557a",
                activeforeground=self.TEXT,
                relief="flat",
                width=10,
                pady=4,
            )
            launch_button.pack(side="left", padx=(0, 8))
            self.launch_buttons[app_key] = launch_button

            close_button = tk.Button(
                actions,
                text="Close",
                command=lambda current=app_key: self.close_app(current),
                bg="#5b2530",
                fg=self.TEXT,
                activebackground="#7a2f3e",
                activeforeground=self.TEXT,
                relief="flat",
                width=10,
                pady=4,
                state="disabled",
            )
            close_button.pack(side="left")
            self.close_buttons[app_key] = close_button

        footer = tk.Label(
            outer,
            text="Tip: keep this menu open while racing so you can restart overlays without touching separate files.",
            font=("Segoe UI", 9),
            fg=self.ACCENT,
            bg=self.BG,
            justify="left",
            wraplength=500,
        )
        footer.pack(anchor="w", pady=(12, 0))

    def launch_app(self, app_key: str) -> None:
        process = self.processes.get(app_key)
        if process is not None and process.poll() is None:
            self._set_status(app_key, f"Already running (PID {process.pid})")
            return

        creationflags = 0
        if os.name == "nt":
            creationflags = getattr(subprocess, "CREATE_NEW_PROCESS_GROUP", 0)

        process = subprocess.Popen(
            [sys.executable, str(Path(__file__).resolve()), app_key],
            creationflags=creationflags,
        )
        self.processes[app_key] = process
        self._set_status(app_key, f"Running (PID {process.pid})")

    def close_app(self, app_key: str) -> None:
        process = self.processes.get(app_key)
        if process is None or process.poll() is not None:
            self.processes.pop(app_key, None)
            self._set_status(app_key, "Closed")
            return

        try:
            process.terminate()
            process.wait(timeout=3)
        except subprocess.TimeoutExpired:
            process.kill()
            process.wait(timeout=3)
        finally:
            self.processes.pop(app_key, None)
            self._set_status(app_key, "Closed")

    def _set_status(self, app_key: str, text: str) -> None:
        self.status_vars[app_key].set(text)
        running = text.startswith("Running") or text.startswith("Already running")
        self.launch_buttons[app_key].configure(state="disabled" if running else "normal")
        self.close_buttons[app_key].configure(state="normal" if running else "disabled")

    def _poll_processes(self) -> None:
        for app_key, _label in APP_DEFINITIONS:
            process = self.processes.get(app_key)
            if process is None:
                continue
            return_code = process.poll()
            if return_code is None:
                continue
            self.processes.pop(app_key, None)
            self._set_status(app_key, f"Closed (exit {return_code})")
        self.root.after(1000, self._poll_processes)

    def _on_close(self) -> None:
        for app_key in list(self.processes):
            self.close_app(app_key)
        self.root.destroy()

    def run(self) -> int:
        self.root.mainloop()
        return 0


def main(argv: Optional[list[str]] = None) -> int:
    args = list(sys.argv[1:] if argv is None else argv)
    if args:
        return _run_embedded_app(args[0])
    return NishizumiSuiteLauncher().run()


if __name__ == "__main__":
    raise SystemExit(main())
